// ---------- Utilidades ----------
// Acepta texto pegado tipo "4.700106557705187, -74.07832849214572"
// (también tolera separadores con espacio simple, tab, o múltiples espacios)
function parsearCoordenadas(texto) {
  if (!texto) return null;
  const partes = texto.trim().split(/[,;\s]+/).filter(Boolean);
  if (partes.length !== 2) return null;
  const lat = parseFloat(partes[0]);
  const lng = parseFloat(partes[1]);
  if (Number.isNaN(lat) || Number.isNaN(lng)) return null;
  if (lat < -90 || lat > 90 || lng < -180 || lng > 180) return null;
  return { lat, lng };
}

function haversine(lat1, lng1, lat2, lng2) {
  const R = 6371000;
  const toRad = (d) => (d * Math.PI) / 180;
  const dLat = toRad(lat2 - lat1);
  const dLng = toRad(lng2 - lng1);
  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLng / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

function fmtDist(m) {
  if (m == null) return "—";
  if (m < 1000) return `${Math.round(m)} m`;
  return `${(m / 1000).toFixed(2)} km`;
}

function fmtFecha(iso) {
  const d = new Date(iso);
  return d.toLocaleDateString("es-CO", { day: "2-digit", month: "short", year: "numeric" });
}
function fmtFechaExport(iso) {
  const d = new Date(iso);
  const dd = String(d.getDate()).padStart(2, "0");
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const yyyy = d.getFullYear();
  return `${dd}/${mm}/${yyyy}`;
}
function fmtHora(iso) {
  const d = new Date(iso);
  return d.toLocaleTimeString("es-CO", { hour: "2-digit", minute: "2-digit", second: "2-digit" });
}

function toDateKey(d) {
  const x = new Date(d);
  return `${x.getFullYear()}-${String(x.getMonth() + 1).padStart(2, "0")}-${String(x.getDate()).padStart(2, "0")}`;
}

function minutosDeDiferencia(timestampISO, horaEsperadaHHMM) {
  if (!horaEsperadaHHMM) return null;
  const t = new Date(timestampISO);
  const [h, m] = horaEsperadaHHMM.split(":").map(Number);
  const esperado = new Date(t);
  esperado.setHours(h, m, 0, 0);
  return Math.round((t - esperado) / 60000); // positivo = tarde, negativo = temprano
}

const TOLERANCIA_MIN = 10; // minutos de tolerancia antes de considerar "tarde"

// Resuelve qué horario aplica para un mensajero en una fecha dada:
// 1) si tiene un turno asignado ese día, usa ese turno
// 2) si no, cae al horario base del mensajero
function resolverHorario(mensajeroNombre, fechaISO, mensajeros, turnos, asignaciones) {
  const fecha = toDateKey(fechaISO);
  const asign = asignaciones.find((a) => a.mensajero === mensajeroNombre && a.fecha === fecha);
  if (asign) {
    const turno = turnos.find((t) => t.id === asign.turnoId);
    if (turno) return { horaEntrada: turno.horaEntrada, horaSalida: turno.horaSalida, turnoNombre: turno.nombre, origen: "turno" };
  }
  const mj = mensajeros.find((m) => m.nombre === mensajeroNombre);
  if (mj) return { horaEntrada: mj.horaEntrada, horaSalida: mj.horaSalida, turnoNombre: null, origen: "base" };
  return null;
}

function calcularMetricas(registros, mensajeros, puntos, desde, hasta, turnos = [], asignaciones = []) {
  const inRange = registros.filter((r) => {
    const t = new Date(r.timestamp).getTime();
    return t >= desde.getTime() && t <= hasta.getTime();
  });

  const entradas = inRange.filter((r) => r.tipo === "entrada");
  const salidas = inRange.filter((r) => r.tipo === "salida");

  let puntuales = 0, tardios = 0;
  const detalle = [];

  entradas.forEach((r) => {
    const horario = resolverHorario(r.mensajero, r.timestamp, mensajeros, turnos, asignaciones);
    const diff = horario ? minutosDeDiferencia(r.timestamp, horario.horaEntrada) : null;
    const esTarde = diff != null && diff > TOLERANCIA_MIN;
    if (diff != null) {
      if (esTarde) tardios++; else puntuales++;
    }
    const p = puntos.find((x) => x.id === r.puntoId);
    const dist = p ? haversine(r.lat, r.lng, p.lat, p.lng) : null;
    detalle.push({ ...r, diffMin: diff, esTarde, distancia: dist, puntoNombre: p ? `${p.codigo} ${p.nombre}` : "—", turnoNombre: horario?.turnoNombre });
  });

  salidas.forEach((r) => {
    const p = puntos.find((x) => x.id === r.puntoId);
    const dist = p ? haversine(r.lat, r.lng, p.lat, p.lng) : null;
    const horario = resolverHorario(r.mensajero, r.timestamp, mensajeros, turnos, asignaciones);
    detalle.push({ ...r, diffMin: null, esTarde: false, distancia: dist, puntoNombre: p ? `${p.codigo} ${p.nombre}` : "—", turnoNombre: horario?.turnoNombre });
  });

  const fueraDeRango = inRange.filter((r) => {
    const p = puntos.find((x) => x.id === r.puntoId);
    if (!p) return false;
    return haversine(r.lat, r.lng, p.lat, p.lng) > 150;
  }).length;

  const totalConHora = puntuales + tardios;
  const pctPuntualidad = totalConHora > 0 ? Math.round((puntuales / totalConHora) * 100) : null;

  return {
    totalRegistros: inRange.length,
    totalEntradas: entradas.length,
    totalSalidas: salidas.length,
    puntuales,
    tardios,
    pctPuntualidad,
    fueraDeRango,
    detalle: detalle.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp)),
  };
}

function uid() {
  return Math.random().toString(36).slice(2, 10) + Date.now().toString(36);
}

