// ---------- Mini mapa SVG (sin dependencias externas) ----------
function MiniMap({ markerA, markerB, labelA = "Marcación", labelB = "Punto" }) {
  // Proyección simple equirectangular local centrada en el punto medio
  const pts = [markerA, markerB].filter(Boolean);
  if (pts.length === 0) return null;
  const lats = pts.map((p) => p.lat);
  const lngs = pts.map((p) => p.lng);
  const latC = (Math.min(...lats) + Math.max(...lats)) / 2;
  const lngC = (Math.min(...lngs) + Math.max(...lngs)) / 2;
  const spanLat = Math.max(Math.max(...lats) - Math.min(...lats), 0.0025);
  const spanLng = Math.max(Math.max(...lngs) - Math.min(...lngs), 0.0025);
  const span = Math.max(spanLat, spanLng) * 1.8;
  const W = 400, H = 260, PAD = 40;

  function project(lat, lng) {
    const x = PAD + ((lng - (lngC - span / 2)) / span) * (W - 2 * PAD);
    const y = H - PAD - ((lat - (latC - span / 2)) / span) * (H - 2 * PAD);
    return [x, y];
  }

  const [ax, ay] = markerA ? project(markerA.lat, markerA.lng) : [null, null];
  const [bx, by] = markerB ? project(markerB.lat, markerB.lng) : [null, null];

  // líneas de cuadrícula
  const grid = [];
  for (let i = 1; i < 5; i++) {
    grid.push(<line key={"v" + i} x1={(W / 5) * i} y1={0} x2={(W / 5) * i} y2={H} stroke="var(--map-grid)" strokeWidth="1" />);
    grid.push(<line key={"h" + i} x1={0} y1={(H / 4) * i} x2={W} y2={(H / 4) * i} stroke="var(--map-grid)" strokeWidth="1" />);
  }

  return (
    <svg viewBox={`0 0 ${W} ${H}`} style={{ width: "100%", height: "auto", display: "block", borderRadius: 10 }}>
      <defs>
        <style>{`
          .mm-bg { fill: var(--map-bg); }
        `}</style>
      </defs>
      <rect className="mm-bg" x="0" y="0" width={W} height={H} />
      {grid}
      {markerA && markerB && (
        <line x1={ax} y1={ay} x2={bx} y2={by} stroke="var(--accent)" strokeWidth="2" strokeDasharray="5 5" opacity="0.7" />
      )}
      {markerB && (
        <g transform={`translate(${bx},${by})`}>
          <circle r="3" fill="var(--ink)" opacity="0.25" />
          {/* Pin Cruz Verde: gota plateada con círculo interior y cruz verde, sin cinta */}
          <g transform="translate(-15,-46)">
            <path
              d="M15 0 C 6.7 0 0 6.7 0 15 C 0 25 15 42 15 42 C 15 42 30 25 30 15 C 30 6.7 23.3 0 15 0 Z"
              fill="#C9CDD3" stroke="#8B8F96" strokeWidth="1"
            />
            <circle cx="15" cy="15" r="11.5" fill="#D7DADE" stroke="#9CA0A6" strokeWidth="1" />
            <circle cx="15" cy="15" r="9.5" fill="#E3E5E8" />
            <path d="M11.5 6 H18.5 V11.5 H24 V18.5 H18.5 V24 H11.5 V18.5 H6 V11.5 H11.5 Z" fill="#1E8A3C" />
          </g>
          <text x="0" y="-50" textAnchor="middle" fontSize="11" fontWeight="700" fill="var(--ink)">{labelB}</text>
        </g>
      )}
      {markerA && (
        <g transform={`translate(${ax},${ay})`}>
          <circle r="9" fill="var(--accent)" opacity="0.18" />
          <circle r="5" fill="var(--accent)" stroke="white" strokeWidth="2" />
          <text x="0" y="-14" textAnchor="middle" fontSize="11" fontWeight="700" fill="var(--ink)">{labelA}</text>
        </g>
      )}
    </svg>
  );
}

// ---------- Cámara ----------
// Redimensiona y comprime una imagen para que sea liviana sin perder
// legibilidad en el panel admin. Apunta a un peso objetivo ajustando
// la calidad JPEG de forma iterativa.
const FOTO_MAX_ANCHO = 1600; // px — buena calidad para zoom en el panel
const FOTO_PESO_OBJETIVO_KB = 350;

function comprimirFoto(video, canvas) {
  const escala = Math.min(1, FOTO_MAX_ANCHO / video.videoWidth);
  canvas.width = Math.round(video.videoWidth * escala);
  canvas.height = Math.round(video.videoHeight * escala);
  const ctx = canvas.getContext("2d");
  ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

  const nitidez = medirNitidez(ctx, canvas.width, canvas.height);

  let calidad = 0.88;
  let dataUrl = canvas.toDataURL("image/jpeg", calidad);
  let pesoKB = Math.round((dataUrl.length * 0.75) / 1024); // base64 ≈ 1.33x el binario

  // Si sigue pesando más de lo deseado, bajar calidad en pasos hasta un mínimo razonable
  while (pesoKB > FOTO_PESO_OBJETIVO_KB && calidad > 0.50) {
    calidad -= 0.1;
    dataUrl = canvas.toDataURL("image/jpeg", calidad);
    pesoKB = Math.round((dataUrl.length * 0.75) / 1024);
  }

  return { dataUrl, pesoKB, ancho: canvas.width, alto: canvas.height, nitidez };
}

// Estima qué tan nítida es la imagen analizando el contraste de bordes
// (una versión simplificada del operador Laplaciano). Fotos nítidas tienen
// transiciones de brillo bruscas entre píxeles vecinos; las borrosas, suaves.
// Trabaja sobre una rejilla muestreada (no cada píxel) para que sea rápido
// incluso en celulares de gama baja.
const UMBRAL_BORROSA = 18; // por debajo de este puntaje, se considera probablemente borrosa

function medirNitidez(ctx, width, height) {
  try {
    const paso = 4; // muestrea 1 de cada 4 píxeles en cada eje
    const data = ctx.getImageData(0, 0, width, height).data;
    let suma = 0;
    let sumaCuadrados = 0;
    let n = 0;

    function gris(x, y) {
      const i = (y * width + x) * 4;
      return (data[i] + data[i + 1] + data[i + 2]) / 3;
    }

    for (let y = paso; y < height - paso; y += paso) {
      for (let x = paso; x < width - paso; x += paso) {
        // diferencia con el vecino horizontal y vertical (gradiente simple)
        const centro = gris(x, y);
        const derecha = gris(x + paso, y);
        const abajo = gris(x, y + paso);
        const dx = centro - derecha;
        const dy = centro - abajo;
        const grad = Math.sqrt(dx * dx + dy * dy);
        suma += grad;
        sumaCuadrados += grad * grad;
        n++;
      }
    }

    if (n === 0) return null;
    const media = suma / n;
    const varianza = sumaCuadrados / n - media * media;
    // normalizamos a una escala aproximada 0-100 para que el umbral sea legible
    return Math.round(Math.sqrt(Math.max(varianza, 0)));
  } catch (e) {
    return null; // si falla el análisis (ej. canvas no soportado), no bloqueamos el flujo
  }
}

function CameraCapture({ onCapture, onCancel }) {
  const videoRef = useRef(null);
  const canvasRef = useRef(null);
  const streamRef = useRef(null);
  const [ready, setReady] = useState(false);
  const [error, setError] = useState(null);
  const [optimizando, setOptimizando] = useState(false);
  const [revision, setRevision] = useState(null); // { dataUrl, pesoKB } mientras se revisa antes de confirmar

  useEffect(() => {
    let mounted = true;
    navigator.mediaDevices
      ?.getUserMedia({ video: { facingMode: "environment", width: { ideal: 1920 }, height: { ideal: 1080 } }, audio: false })
      .then((stream) => {
        if (!mounted) return;
        streamRef.current = stream;
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          videoRef.current.play();
          setReady(true);
        }
      })
      .catch(() => setError("No se pudo acceder a la cámara. Revisa los permisos del navegador."));
    return () => {
      mounted = false;
      streamRef.current?.getTracks().forEach((t) => t.stop());
    };
  }, []);

  function takePhoto() {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    if (!video || !canvas) return;
    setOptimizando(true);
    // pequeño respiro de UI para que se vea el estado "optimizando" antes del trabajo síncrono
    requestAnimationFrame(() => {
      const { dataUrl, pesoKB, nitidez } = comprimirFoto(video, canvas);
      setOptimizando(false);
      setRevision({ dataUrl, pesoKB, nitidez }); // mostrar a pantalla completa antes de confirmar
    });
  }

  function repetir() {
    setRevision(null);
    // la cámara sigue activa (el stream no se detuvo), así que solo volvemos a mostrar el visor
  }

  function confirmar() {
    streamRef.current?.getTracks().forEach((t) => t.stop());
    onCapture(revision.dataUrl, revision.pesoKB);
  }

  // Paso de revisión: foto a pantalla completa para detectar borrón antes de confirmar
  if (revision) {
    const posibleBorron = revision.nitidez != null && revision.nitidez < UMBRAL_BORROSA;
    return (
      <div style={{ position: "fixed", inset: 0, background: "#000", zIndex: 100, display: "flex", flexDirection: "column" }}>
        <div style={{ flex: 1, position: "relative", overflow: "hidden" }}>
          <img src={revision.dataUrl} alt="Vista previa" style={{ width: "100%", height: "100%", objectFit: "contain", background: "#000" }} />
          <div style={{ position: "absolute", top: 16, left: 16, right: 16, textAlign: "center" }}>
            {posibleBorron ? (
              <span style={{ background: "var(--accent)", color: "white", fontSize: 12, fontWeight: 700, padding: "8px 14px", borderRadius: 20, fontFamily: "var(--font-body)", display: "inline-flex", alignItems: "center", gap: 6 }}>
                <AlertTriangle size={14} /> Parece borrosa — puedes repetirla o usarla igual
              </span>
            ) : (
              <span style={{ background: "rgba(0,0,0,0.55)", color: "white", fontSize: 12, padding: "6px 12px", borderRadius: 20, fontFamily: "var(--font-body)" }}>
                ¿Se ve nítida? Revisa antes de continuar
              </span>
            )}
          </div>
        </div>
        <div style={{ padding: 20, display: "flex", justifyContent: "center", gap: 14, alignItems: "center", background: "#000" }}>
          <button
            onClick={repetir}
            style={{ flex: 1, maxWidth: 160, display: "flex", alignItems: "center", justifyContent: "center", gap: 8, background: posibleBorron ? "var(--accent)" : "rgba(255,255,255,0.15)", border: posibleBorron ? "none" : "1px solid rgba(255,255,255,0.3)", borderRadius: 10, padding: "14px", color: "white", fontSize: 14, fontWeight: 700, fontFamily: "var(--font-body)", cursor: "pointer" }}
          >
            <Camera size={17} /> Repetir
          </button>
          <button
            onClick={confirmar}
            style={{ flex: 1, maxWidth: 160, display: "flex", alignItems: "center", justifyContent: "center", gap: 8, background: posibleBorron ? "rgba(255,255,255,0.15)" : "var(--accent)", border: posibleBorron ? "1px solid rgba(255,255,255,0.3)" : "none", borderRadius: 10, padding: "14px", color: "white", fontSize: 14, fontWeight: 700, fontFamily: "var(--font-body)", cursor: "pointer" }}
          >
            <Check size={17} /> Usar esta foto
          </button>
        </div>
      </div>
    );
  }

  return (
    <div style={{ position: "fixed", inset: 0, background: "#000", zIndex: 100, display: "flex", flexDirection: "column" }}>
      <div style={{ flex: 1, position: "relative", overflow: "hidden" }}>
        {error ? (
          <div style={{ color: "white", padding: 24, textAlign: "center", marginTop: 80, fontFamily: "var(--font-body)" }}>
            <AlertTriangle size={28} style={{ marginBottom: 10 }} />
            <div>{error}</div>
          </div>
        ) : (
          <video ref={videoRef} style={{ width: "100%", height: "100%", objectFit: "cover" }} playsInline muted />
        )}
        <canvas ref={canvasRef} style={{ display: "none" }} />
        {optimizando && (
          <div style={{ position: "absolute", inset: 0, background: "rgba(0,0,0,0.55)", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 10 }}>
            <Loader2 size={28} color="white" className="spin" />
            <div style={{ color: "white", fontSize: 13, fontFamily: "var(--font-body)" }}>Optimizando foto…</div>
          </div>
        )}
      </div>
      <div style={{ padding: 20, display: "flex", justifyContent: "center", gap: 24, alignItems: "center", background: "#000" }}>
        <button onClick={onCancel} style={{ background: "rgba(255,255,255,0.15)", border: "none", borderRadius: "50%", width: 52, height: 52, color: "white", display: "flex", alignItems: "center", justifyContent: "center" }}>
          <X size={22} />
        </button>
        <button
          onClick={takePhoto}
          disabled={!ready || optimizando}
          style={{
            background: ready && !optimizando ? "var(--accent)" : "#555",
            border: "4px solid white",
            borderRadius: "50%",
            width: 76,
            height: 76,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
          }}
        >
          <Camera size={28} color="white" />
        </button>
        <div style={{ width: 52 }} />
      </div>
    </div>
  );
}

// ---------- Sello visual de confirmación ----------
