// ---------- Versión A: paso de aceptación para conductores ya en la lista ----------
// El conductor ya eligió su nombre de la lista (admin lo creó antes).
// Antes de pasar a marcar, debe aceptar términos y condiciones — cada vez.
function AceptarTerminos({ mensajero, onAceptar, onVolver }) {
  const [aceptaTerminos, setAceptaTerminos] = useState(false);
  const [error, setError] = useState("");

  function continuar() {
    if (!aceptaTerminos) { setError("Debes aceptar los Términos y condiciones y el Contrato de arrendamiento para continuar."); return; }
    setError("");
    onAceptar();
  }

  return (
    <div style={{ minHeight: "100%", display: "flex", flexDirection: "column", padding: "32px 20px" }}>
      <div style={{ textAlign: "center", marginBottom: 26 }}>
        <img src={LOGO_SRC} alt="NVO" style={{ width: "auto", height: 48, objectFit: "contain", marginBottom: 14 }} />
        <div style={{ fontFamily: "var(--font-display)", fontSize: 13, letterSpacing: "0.12em", color: "var(--muted)", textTransform: "uppercase", marginBottom: 6 }}>
          Bitácora de ruta
        </div>
        <div style={{ fontFamily: "var(--font-display)", fontSize: 20, fontWeight: 800, color: "var(--ink)" }}>
          Hola, {mensajero.split(" ")[0]}
        </div>
        <div style={{ fontSize: 13, color: "var(--muted)", marginTop: 6 }}>
          Antes de continuar, confirma que aceptas lo siguiente.
        </div>
      </div>

      <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
        <BloqueTerminos checked={aceptaTerminos} onChange={setAceptaTerminos} />
        {error && (
          <div style={{ fontSize: 12, color: "var(--accent)", display: "flex", alignItems: "center", gap: 6 }}>
            <AlertTriangle size={13} /> {error}
          </div>
        )}
        <button onClick={continuar} style={{ ...btnPrimary(), background: "var(--accent)" }}>
          Continuar
        </button>
        <button onClick={onVolver} style={{ background: "none", border: "none", color: "var(--muted)", fontSize: 13, textDecoration: "underline", cursor: "pointer" }}>
          No soy yo
        </button>
      </div>
    </div>
  );
}

// ---------- Bloque reutilizable de términos y condiciones ----------
function BloqueTerminos({ checked, onChange }) {
  return (
    <div style={{ background: "var(--bg)", border: "1px solid var(--line)", borderRadius: 10, padding: 12 }}>
      <div style={{ fontSize: 12, color: "var(--ink)", lineHeight: 1.6, marginBottom: 8 }}>
        <a href="https://drive.google.com/file/d/1nmxfaUR9juQsdFwEgFLtoKmV_ChQXVRb/view" target="_blank" rel="noopener noreferrer" style={{ color: "var(--accent)", fontWeight: 700, textDecoration: "underline" }}>
          Términos y condiciones
        </a>
        {" · "}
        <a href="https://drive.google.com/file/d/1nGM7eruKl_Ewv3NaIHG8iHcsac0AJSyC/view" target="_blank" rel="noopener noreferrer" style={{ color: "var(--accent)", fontWeight: 700, textDecoration: "underline" }}>
          Contrato de arrendamiento del vehículo
        </a>
      </div>
      <label style={{ display: "flex", alignItems: "flex-start", gap: 8, fontSize: 12.5, color: "var(--ink)", lineHeight: 1.5, cursor: "pointer" }}>
        <input
          type="checkbox"
          checked={checked}
          onChange={(e) => onChange(e.target.checked)}
          style={{ marginTop: 2, width: 16, height: 16, flexShrink: 0, accentColor: "var(--accent)" }}
        />
        Al continuar, confirmas que aceptas nuestros Términos y condiciones y el Contrato de arrendamiento.
      </label>
    </div>
  );
}

// ---------- Versión B: auto-registro sin lista previa ----------
// El conductor escribe su nombre y placa la primera vez; quedan
// recordados en este dispositivo (almacenamiento personal, no compartido)
// para no tener que escribirlos cada vez.
function RegistroAutonomo({ onListo }) {
  const [cargando, setCargando] = useState(true);
  const [datosGuardados, setDatosGuardados] = useState(null);
  const [nombre, setNombre] = useState("");
  const [placa, setPlaca] = useState("");
  const [editando, setEditando] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    (async () => {
      try {
        const r = await storeGet("perfil_conductor", false); // false = personal de este dispositivo
        if (r?.value) {
          const datos = JSON.parse(r.value);
          setDatosGuardados(datos);
          setNombre(datos.nombre || "");
          setPlaca(datos.placa || "");
        }
      } catch (e) {
        // sin datos guardados todavía, es la primera vez en este dispositivo
      }
      setCargando(false);
    })();
  }, []);

  async function guardarYContinuar() {
    const nombreLimpio = nombre.trim();
    const placaLimpia = placa.trim().toUpperCase();
    if (!nombreLimpio) { setError("Escribe tu nombre completo."); return; }
    if (!placaLimpia) { setError("Escribe la placa de tu vehículo."); return; }
    setError("");
    const datos = { nombre: nombreLimpio, placa: placaLimpia };
    try {
      await storeSet("perfil_conductor", JSON.stringify(datos), false);
    } catch (e) {
      console.error(e);
    }
    onListo(datos);
  }

  if (cargando) {
    return (
      <div style={{ display: "flex", alignItems: "center", justifyContent: "center", height: "100%", color: "var(--muted)", fontSize: 13 }}>
        Cargando…
      </div>
    );
  }

  // Ya hay datos guardados de una visita anterior y no está editando: pantalla de bienvenida rápida
  if (datosGuardados && !editando) {
    return (
      <div style={{ minHeight: "100%", display: "flex", flexDirection: "column", padding: "32px 20px", alignItems: "center", justifyContent: "center", textAlign: "center" }}>
        <img src={LOGO_SRC} alt="NVO" style={{ width: "auto", height: 48, objectFit: "contain", marginBottom: 18 }} />
        <div style={{ fontFamily: "var(--font-display)", fontSize: 13, letterSpacing: "0.12em", color: "var(--muted)", textTransform: "uppercase", marginBottom: 8 }}>
          ¡Hola de nuevo!
        </div>
        <div style={{ width: 56, height: 56, borderRadius: "50%", background: "var(--accent-soft)", display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "var(--font-display)", fontWeight: 800, color: "var(--accent)", fontSize: 18, marginBottom: 14 }}>
          {datosGuardados.nombre.split(" ").map((p) => p[0]).join("").slice(0, 2)}
        </div>
        <div style={{ fontFamily: "var(--font-display)", fontSize: 20, fontWeight: 800, color: "var(--ink)", marginBottom: 4 }}>
          {datosGuardados.nombre}
        </div>
        <div style={{ fontSize: 13, color: "var(--muted)", marginBottom: 28, fontFamily: "monospace" }}>
          Placa {datosGuardados.placa}
        </div>
        <button onClick={() => onListo(datosGuardados)} style={{ ...btnPrimary(), background: "var(--accent)", marginBottom: 10 }}>
          Continuar
        </button>
        <button onClick={() => setEditando(true)} style={{ background: "none", border: "none", color: "var(--muted)", fontSize: 13, textDecoration: "underline", cursor: "pointer" }}>
          No soy yo / corregir datos
        </button>
      </div>
    );
  }

  // Primera vez en este dispositivo, o corrigiendo datos: formulario de registro
  return (
    <div style={{ minHeight: "100%", display: "flex", flexDirection: "column", padding: "32px 20px" }}>
      <div style={{ textAlign: "center", marginBottom: 30 }}>
        <img src={LOGO_SRC} alt="NVO" style={{ width: "auto", height: 48, objectFit: "contain", marginBottom: 14 }} />
        <div style={{ fontFamily: "var(--font-display)", fontSize: 13, letterSpacing: "0.12em", color: "var(--muted)", textTransform: "uppercase", marginBottom: 6 }}>
          Bitácora de ruta
        </div>
        <div style={{ fontFamily: "var(--font-display)", fontSize: 22, fontWeight: 800, color: "var(--ink)" }}>
          {datosGuardados ? "Corrige tus datos" : "Regístrate para empezar"}
        </div>
        <div style={{ fontSize: 13, color: "var(--muted)", marginTop: 6 }}>
          Solo lo harás una vez en este celular.
        </div>
      </div>

      <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
        <div>
          <label style={{ fontSize: 11, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", color: "var(--muted)", fontFamily: "var(--font-display)" }}>
            Nombres y apellidos
          </label>
          <input
            autoFocus
            placeholder="Ej. Carlos Ramírez"
            value={nombre}
            onChange={(e) => setNombre(e.target.value)}
            style={{ ...inputStyle(), width: "100%", marginTop: 6, padding: "13px 14px", fontSize: 15 }}
          />
        </div>
        <div>
          <label style={{ fontSize: 11, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", color: "var(--muted)", fontFamily: "var(--font-display)" }}>
            Placa del vehículo
          </label>
          <input
            placeholder="Ej. ABC123"
            value={placa}
            onChange={(e) => setPlaca(e.target.value.toUpperCase())}
            style={{ ...inputStyle(), width: "100%", marginTop: 6, padding: "13px 14px", fontSize: 15, fontFamily: "monospace", letterSpacing: "0.05em" }}
          />
        </div>
        {error && (
          <div style={{ fontSize: 12, color: "var(--accent)", display: "flex", alignItems: "center", gap: 6 }}>
            <AlertTriangle size={13} /> {error}
          </div>
        )}

        <button onClick={guardarYContinuar} style={{ ...btnPrimary(), background: "var(--accent)", marginTop: 6 }}>
          {datosGuardados ? "Guardar cambios" : "Continuar"}
        </button>
        {datosGuardados && editando && (
          <button onClick={() => setEditando(false)} style={{ background: "none", border: "none", color: "var(--muted)", fontSize: 13, textDecoration: "underline", cursor: "pointer" }}>
            Cancelar
          </button>
        )}
      </div>
    </div>
  );
}

// ---------- Vista: panel mensajero (marcar entrada/salida) ----------
function PanelMensajero({ mensajero, placa, mensajeros, puntos, ciudadDispositivo, registros, onAddRegistro, onLogout }) {
  const datosMensajero = mensajeros.find((m) => m.nombre === mensajero);
  const ciudadEfectiva = datosMensajero?.ciudad || ciudadDispositivo || null;
  const puntosCiudad = puntos
    .filter((p) => !ciudadEfectiva || p.ciudad === ciudadEfectiva)
    .sort((a, b) => {
      const numA = parseInt(a.codigo, 10);
      const numB = parseInt(b.codigo, 10);
      if (!isNaN(numA) && !isNaN(numB)) return numA - numB;
      return a.codigo.localeCompare(b.codigo);
    });
  const [puntoId, setPuntoId] = useState(puntosCiudad[0]?.id || "");
  const [tipo, setTipo] = useState(null); // "entrada" | "salida"
  const [showCamera, setShowCamera] = useState(false);
  const [photo, setPhoto] = useState(null);
  const [photoKB, setPhotoKB] = useState(null);
  const [coords, setCoords] = useState(null);
  const [gpsError, setGpsError] = useState(null);
  const [gpsLoading, setGpsLoading] = useState(false);
  const [sello, setSello] = useState(null);
  const [saving, setSaving] = useState(false);

  const propios = registros
    .filter((r) => r.mensajero === mensajero)
    .sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));
  const hoy = new Date().toDateString();
  const deHoy = propios.filter((r) => new Date(r.timestamp).toDateString() === hoy);

  function iniciar(tipoSel) {
    setTipo(tipoSel);
    setPhoto(null);
    setPhotoKB(null);
    setCoords(null);
    setGpsError(null);
    pedirUbicacion();
  }

  function pedirUbicacion() {
    setGpsLoading(true);
    setGpsError(null);
    if (!navigator.geolocation) {
      setGpsError("Este dispositivo no soporta geolocalización.");
      setGpsLoading(false);
      return;
    }
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        setCoords({ lat: pos.coords.latitude, lng: pos.coords.longitude, accuracy: pos.coords.accuracy });
        setGpsLoading(false);
      },
      (err) => {
        setGpsError("No se pudo obtener tu ubicación. Activa el GPS y los permisos de localización.");
        setGpsLoading(false);
      },
      { enableHighAccuracy: true, timeout: 12000 }
    );
  }

  async function confirmar() {
    if (!coords || !photo || !tipo || !puntoId) return;
    setSaving(true);
    const registro = {
      id: uid(),
      mensajero,
      placa: placa || null,
      puntoId,
      tipo,
      lat: coords.lat,
      lng: coords.lng,
      accuracy: coords.accuracy,
      foto: photo,
      timestamp: new Date().toISOString(),
    };
    await onAddRegistro(registro);
    setSaving(false);
    setSello(registro);
    setTipo(null);
    setPhoto(null);
    setPhotoKB(null);
    setCoords(null);
  }

  const punto = puntosCiudad.find((p) => p.id === puntoId);
  const yaEntroHoy = deHoy.some((r) => r.tipo === "entrada");
  const yaSalioHoy = deHoy.some((r) => r.tipo === "salida");

  return (
    <div style={{ minHeight: "100%", display: "flex", flexDirection: "column" }}>
      <div style={{ padding: "16px 18px 14px", borderBottom: "1px solid var(--line)", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <img src={LOGO_SRC} alt="NVO" style={{ width: "auto", height: 28, objectFit: "contain" }} />
          <div>
            <div style={{ fontSize: 11, color: "var(--muted)", letterSpacing: "0.08em", textTransform: "uppercase", fontFamily: "var(--font-display)" }}>
              Mensajero{ciudadEfectiva ? ` · ${ciudadEfectiva}` : ""}{placa ? ` · ${placa.toUpperCase()}` : ""}
            </div>
            <div style={{ fontSize: 16, fontWeight: 700, color: "var(--ink)" }}>{mensajero}</div>
          </div>
        </div>
        <button onClick={onLogout} style={{ background: "none", border: "none", color: "var(--muted)", fontSize: 13, cursor: "pointer", fontFamily: "var(--font-body)" }}>
          Cambiar
        </button>
      </div>

      <div style={{ padding: "18px 18px 0" }}>
        <label style={{ fontSize: 11, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", color: "var(--muted)", fontFamily: "var(--font-display)" }}>
          Punto asignado
        </label>
        <select
          value={puntoId}
          onChange={(e) => setPuntoId(e.target.value)}
          style={{
            width: "100%",
            marginTop: 6,
            padding: "12px 14px",
            borderRadius: 10,
            border: "1px solid var(--line)",
            fontSize: 15,
            fontFamily: "var(--font-body)",
            color: "var(--ink)",
            background: "var(--paper)",
          }}
        >
          {puntosCiudad.map((p) => (
            <option key={p.id} value={p.id}>{p.codigo} — {p.nombre}</option>
          ))}
        </select>
      </div>

      <div style={{ padding: "20px 18px", display: "flex", gap: 12 }}>
        <button
          onClick={() => iniciar("entrada")}
          disabled={yaEntroHoy}
          style={{
            flex: 1,
            background: yaEntroHoy ? "var(--line)" : "var(--ok)",
            color: yaEntroHoy ? "var(--muted)" : "white",
            border: "none",
            borderRadius: 12,
            padding: "20px 12px",
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            gap: 8,
            fontFamily: "var(--font-display)",
            fontWeight: 700,
            fontSize: 13,
            letterSpacing: "0.04em",
            cursor: yaEntroHoy ? "default" : "pointer",
          }}
        >
          <LogIn size={24} />
          {yaEntroHoy ? "ENTRADA MARCADA" : "MARCAR ENTRADA"}
        </button>
        <button
          onClick={() => iniciar("salida")}
          disabled={yaSalioHoy || !yaEntroHoy}
          style={{
            flex: 1,
            background: yaSalioHoy || !yaEntroHoy ? "var(--line)" : "var(--accent)",
            color: yaSalioHoy || !yaEntroHoy ? "var(--muted)" : "white",
            border: "none",
            borderRadius: 12,
            padding: "20px 12px",
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            gap: 8,
            fontFamily: "var(--font-display)",
            fontWeight: 700,
            fontSize: 13,
            letterSpacing: "0.04em",
            cursor: yaSalioHoy || !yaEntroHoy ? "default" : "pointer",
          }}
        >
          <LogOut size={24} />
          {yaSalioHoy ? "SALIDA MARCADA" : "MARCAR SALIDA"}
        </button>
      </div>

      {tipo && (
        <div style={{ margin: "0 18px 18px", border: "1px solid var(--line)", borderRadius: 14, padding: 16, background: "var(--accent-soft)" }}>
          <div style={{ fontFamily: "var(--font-display)", fontWeight: 700, fontSize: 14, marginBottom: 12, color: "var(--ink)" }}>
            {tipo === "entrada" ? "Confirmar entrada" : "Confirmar salida"} — {punto?.codigo} {punto?.nombre}
          </div>

          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10, fontSize: 13 }}>
            <MapPin size={16} color={coords ? "var(--ok)" : "var(--muted)"} />
            {gpsLoading && <span style={{ display: "flex", alignItems: "center", gap: 6, color: "var(--muted)" }}><Loader2 size={14} className="spin" /> Obteniendo ubicación…</span>}
            {coords && <span style={{ color: "var(--ink)", fontFamily: "monospace" }}>{coords.lat.toFixed(5)}, {coords.lng.toFixed(5)} (±{Math.round(coords.accuracy)}m)</span>}
            {gpsError && <span style={{ color: "var(--accent)" }}>{gpsError}</span>}
            {!gpsLoading && (gpsError || coords) && (
              <button onClick={pedirUbicacion} style={{ background: "none", border: "none", color: "var(--ink)", fontSize: 12, textDecoration: "underline", cursor: "pointer" }}>
                Reintentar
              </button>
            )}
          </div>

          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 14 }}>
            {photo ? (
              <>
                <img src={photo} alt="evidencia" style={{ width: 64, height: 64, objectFit: "cover", borderRadius: 8, border: "1px solid var(--line)" }} />
                {photoKB != null && (
                  <div style={{ fontSize: 11, color: "var(--ok)", display: "flex", alignItems: "center", gap: 4 }}>
                    <Check size={13} /> Lista · {photoKB} KB
                  </div>
                )}
              </>
            ) : (
              <button
                onClick={() => setShowCamera(true)}
                style={{ display: "flex", alignItems: "center", gap: 8, background: "var(--paper)", border: "1px dashed var(--muted)", borderRadius: 8, padding: "10px 14px", fontSize: 13, color: "var(--ink)", cursor: "pointer" }}
              >
                <Camera size={16} /> Tomar foto de evidencia
              </button>
            )}
            {photo && (
              <button onClick={() => setShowCamera(true)} style={{ fontSize: 12, color: "var(--muted)", background: "none", border: "none", textDecoration: "underline", cursor: "pointer" }}>
                Repetir
              </button>
            )}
          </div>

          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={() => setTipo(null)} style={{ flex: 1, background: "var(--paper)", border: "1px solid var(--line)", borderRadius: 10, padding: "12px", fontSize: 13, fontWeight: 600, color: "var(--muted)", cursor: "pointer" }}>
              Cancelar
            </button>
            <button
              onClick={confirmar}
              disabled={!coords || !photo || saving}
              style={{
                flex: 2,
                background: !coords || !photo ? "var(--line)" : "var(--ink)",
                color: !coords || !photo ? "var(--muted)" : "var(--paper)",
                border: "none",
                borderRadius: 10,
                padding: "12px",
                fontSize: 14,
                fontWeight: 700,
                cursor: !coords || !photo ? "default" : "pointer",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                gap: 8,
              }}
            >
              {saving ? <Loader2 size={16} className="spin" /> : <Check size={16} />}
              Confirmar {tipo === "entrada" ? "entrada" : "salida"}
            </button>
          </div>
        </div>
      )}

      <div style={{ padding: "0 18px 24px", flex: 1 }}>
        <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", color: "var(--muted)", fontFamily: "var(--font-display)", marginBottom: 10 }}>
          Tus últimas marcaciones
        </div>
        {propios.length === 0 && <div style={{ fontSize: 13, color: "var(--muted)" }}>Aún no tienes marcaciones registradas.</div>}
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          {propios.slice(0, 8).map((r) => {
            const p = puntos.find((x) => x.id === r.puntoId);
            return (
              <div key={r.id} style={{ display: "flex", alignItems: "center", gap: 10, padding: "10px 12px", border: "1px solid var(--line)", borderRadius: 10, background: "var(--paper)" }}>
                <div style={{ width: 32, height: 32, borderRadius: "50%", background: r.tipo === "entrada" ? "var(--ok)" : "var(--accent)", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                  {r.tipo === "entrada" ? <LogIn size={15} color="white" /> : <LogOut size={15} color="white" />}
                </div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontSize: 13, fontWeight: 600, color: "var(--ink)" }}>
                    {r.tipo === "entrada" ? "Entrada" : "Salida"} · {p?.codigo} {p?.nombre}
                  </div>
                  <div style={{ fontSize: 12, color: "var(--muted)" }}>{fmtFecha(r.timestamp)} — {fmtHora(r.timestamp)}</div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {showCamera && (
        <CameraCapture
          onCapture={(d, kb) => { setPhoto(d); setPhotoKB(kb); setShowCamera(false); }}
          onCancel={() => setShowCamera(false)}
        />
      )}
      {sello && (
        <Sello tipo={sello.tipo} registro={sello} punto={puntos.find((p) => p.id === sello.puntoId)} onClose={() => setSello(null)} />
      )}
    </div>
  );
}

// ---------- Mini calendario mensual ----------
const DIAS_SEMANA = ["L", "M", "X", "J", "V", "S", "D"];
const MESES = ["Enero", "Febrero", "Marzo", "Abril", "Mayo", "Junio", "Julio", "Agosto", "Septiembre", "Octubre", "Noviembre", "Diciembre"];

function MiniCalendario({ fechaSeleccionada, onSelectFecha, conteoPorDia }) {
  const [mesVisible, setMesVisible] = useState(new Date(fechaSeleccionada));

  const year = mesVisible.getFullYear();
  const month = mesVisible.getMonth();
  const primerDia = new Date(year, month, 1);
  const ultimoDia = new Date(year, month + 1, 0);
  let offset = primerDia.getDay() - 1;
  if (offset < 0) offset = 6;

  const celdas = [];
  for (let i = 0; i < offset; i++) celdas.push(null);
  for (let d = 1; d <= ultimoDia.getDate(); d++) celdas.push(new Date(year, month, d));

  const hoyKey = toDateKey(new Date());
  const selKey = toDateKey(fechaSeleccionada);

  return (
    <div style={{ background: "var(--paper)", border: "1px solid var(--line)", borderRadius: 12, padding: 14 }}>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 10 }}>
        <button onClick={() => setMesVisible(new Date(year, month - 1, 1))} style={iconBtnStyle()}>
          <ChevronLeft size={16} />
        </button>
        <div style={{ fontFamily: "var(--font-display)", fontWeight: 700, fontSize: 13, color: "var(--ink)" }}>
          {MESES[month]} {year}
        </div>
        <button onClick={() => setMesVisible(new Date(year, month + 1, 1))} style={iconBtnStyle()}>
          <ChevronRight size={16} />
        </button>
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 4, marginBottom: 4 }}>
        {DIAS_SEMANA.map((d) => (
          <div key={d} style={{ textAlign: "center", fontSize: 10, color: "var(--muted)", fontWeight: 700 }}>{d}</div>
        ))}
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 4 }}>
        {celdas.map((fecha, i) => {
          if (!fecha) return <div key={i} />;
          const key = toDateKey(fecha);
          const isToday = key === hoyKey;
          const isSel = key === selKey;
          const conteo = conteoPorDia?.[key] || 0;
          return (
            <button
              key={i}
              onClick={() => onSelectFecha(fecha)}
              style={{
                position: "relative",
                aspectRatio: "1",
                border: isSel ? "2px solid var(--accent)" : isToday ? "1px solid var(--ink)" : "1px solid transparent",
                background: isSel ? "var(--accent-soft)" : "transparent",
                borderRadius: 8,
                fontSize: 12,
                fontWeight: isToday ? 800 : 500,
                color: "var(--ink)",
                cursor: "pointer",
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                justifyContent: "center",
                gap: 2,
              }}
            >
              {fecha.getDate()}
              {conteo > 0 && <span style={{ width: 4, height: 4, borderRadius: "50%", background: "var(--accent)" }} />}
            </button>
          );
        })}
      </div>
    </div>
  );
}

function iconBtnStyle() {
  return { background: "var(--bg)", border: "1px solid var(--line)", borderRadius: 8, width: 28, height: 28, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", color: "var(--ink)" };
}

// ---------- Tarjeta de métrica ----------
function MetricCard({ label, value, sub, color }) {
  return (
    <div style={{ background: "var(--paper)", border: "1px solid var(--line)", borderRadius: 12, padding: "14px 16px" }}>
      <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: "0.05em", textTransform: "uppercase", color: "var(--muted)", fontFamily: "var(--font-display)", marginBottom: 6 }}>
        {label}
      </div>
      <div style={{ fontSize: 26, fontWeight: 800, color: color || "var(--ink)", fontFamily: "var(--font-display)" }}>
        {value}
      </div>
      {sub && <div style={{ fontSize: 11, color: "var(--muted)", marginTop: 2 }}>{sub}</div>}
    </div>
  );
}

// ---------- Dashboard de métricas ----------
function Dashboard({ registros, mensajeros, puntos, turnos, asignaciones, filtroCiudad }) {
  const [periodo, setPeriodo] = useState("dia"); // dia | quincena | mes
  const [fechaRef, setFechaRef] = useState(new Date());

  const registrosCiudad = filtroCiudad === "todas"
    ? registros
    : registros.filter((r) => mensajeros.find((m) => m.nombre === r.mensajero)?.ciudad === filtroCiudad);

  let desde, hasta, etiqueta;
  const y = fechaRef.getFullYear(), m = fechaRef.getMonth(), d = fechaRef.getDate();

  if (periodo === "dia") {
    desde = new Date(y, m, d, 0, 0, 0);
    hasta = new Date(y, m, d, 23, 59, 59);
    etiqueta = fechaRef.toLocaleDateString("es-CO", { day: "2-digit", month: "long", year: "numeric" });
  } else if (periodo === "quincena") {
    if (d <= 15) { desde = new Date(y, m, 1); hasta = new Date(y, m, 15, 23, 59, 59); etiqueta = `1 — 15 de ${MESES[m]} ${y}`; }
    else { desde = new Date(y, m, 16); hasta = new Date(y, m + 1, 0, 23, 59, 59); etiqueta = `16 — ${hasta.getDate()} de ${MESES[m]} ${y}`; }
  } else {
    desde = new Date(y, m, 1);
    hasta = new Date(y, m + 1, 0, 23, 59, 59);
    etiqueta = `${MESES[m]} ${y}`;
  }

  const metricas = calcularMetricas(registrosCiudad, mensajeros, puntos, desde, hasta, turnos, asignaciones);

  function mover(dir) {
    if (periodo === "dia") setFechaRef(new Date(y, m, d + dir));
    else if (periodo === "quincena") setFechaRef(new Date(y, m, d + dir * 15));
    else setFechaRef(new Date(y, m + dir, 1));
  }

  // Resumen por mensajero
  const porMensajero = mensajeros
    .filter((mj) => filtroCiudad === "todas" || mj.ciudad === filtroCiudad)
    .map((mj) => {
      const propios = metricas.detalle.filter((r) => r.mensajero === mj.nombre);
      const entradasProp = propios.filter((r) => r.tipo === "entrada");
      const tardiasProp = entradasProp.filter((r) => r.esTarde).length;
      return { nombre: mj.nombre, ciudad: mj.ciudad, total: propios.length, entradas: entradasProp.length, tardias: tardiasProp };
    });

  return (
    <div style={{ padding: 18 }}>
      <div style={{ display: "flex", gap: 6, marginBottom: 14 }}>
        {[["dia", "Día"], ["quincena", "Quincena"], ["mes", "Mes"]].map(([k, label]) => (
          <button
            key={k}
            onClick={() => setPeriodo(k)}
            style={{
              flex: 1, padding: "8px 10px", borderRadius: 8, fontSize: 12, fontWeight: 700,
              border: periodo === k ? "1px solid var(--ink)" : "1px solid var(--line)",
              background: periodo === k ? "var(--ink)" : "var(--paper)",
              color: periodo === k ? "var(--paper)" : "var(--muted)",
              cursor: "pointer",
            }}
          >
            {label}
          </button>
        ))}
      </div>

      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 16 }}>
        <button onClick={() => mover(-1)} style={iconBtnStyle()}><ChevronLeft size={16} /></button>
        <div style={{ fontSize: 13, fontWeight: 700, color: "var(--ink)", textAlign: "center" }}>{etiqueta}</div>
        <button onClick={() => mover(1)} style={iconBtnStyle()}><ChevronRight size={16} /></button>
      </div>

      <div className="nvo-metric-grid" style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 10 }}>
        <MetricCard label="Puntualidad" value={metricas.pctPuntualidad != null ? `${metricas.pctPuntualidad}%` : "—"} sub={`${metricas.puntuales} a tiempo`} color="var(--ok)" />
        <MetricCard label="Llegadas tarde" value={metricas.tardios} sub={`> ${TOLERANCIA_MIN} min de tolerancia`} color={metricas.tardios > 0 ? "var(--accent)" : "var(--ink)"} />
        <MetricCard label="Marcaciones totales" value={metricas.totalRegistros} sub={`${metricas.totalEntradas} entradas · ${metricas.totalSalidas} salidas`} />
        <MetricCard label="Fuera de zona" value={metricas.fueraDeRango} sub="distancia > 150 m del punto" color={metricas.fueraDeRango > 0 ? "var(--accent)" : "var(--ink)"} />
      </div>

      <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", color: "var(--muted)", fontFamily: "var(--font-display)", margin: "16px 0 8px" }}>
        Por mensajero
      </div>
      <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
        {porMensajero.map((mj) => (
          <div key={mj.nombre} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "10px 12px", border: "1px solid var(--line)", borderRadius: 10, background: "var(--paper)" }}>
            <div>
              <div style={{ fontSize: 13, fontWeight: 700, color: "var(--ink)" }}>{mj.nombre}</div>
              <div style={{ fontSize: 11, color: "var(--muted)" }}>{mj.ciudad} · {mj.entradas} entradas registradas</div>
            </div>
            <div style={{ textAlign: "right" }}>
              {mj.tardias > 0 ? (
                <div style={{ fontSize: 12, fontWeight: 700, color: "var(--accent)" }}>{mj.tardias} tarde{mj.tardias > 1 ? "s" : ""}</div>
              ) : (
                <div style={{ fontSize: 12, fontWeight: 700, color: "var(--ok)" }}>A tiempo</div>
              )}
            </div>
          </div>
        ))}
        {porMensajero.length === 0 && <div style={{ fontSize: 13, color: "var(--muted)" }}>No hay mensajeros para este filtro.</div>}
      </div>
    </div>
  );
}

// ---------- Exportar a Excel ----------
function exportarExcel(registros, mensajeros, puntos, turnos, asignaciones, desde, hasta) {
  const filas = registros
    .filter((r) => {
      const t = new Date(r.timestamp).getTime();
      return t >= desde.getTime() && t <= hasta.getTime();
    })
    .sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp))
    .map((r) => {
      const p = puntos.find((x) => x.id === r.puntoId);
      const mj = mensajeros.find((m) => m.nombre === r.mensajero);
      const horario = resolverHorario(r.mensajero, r.timestamp, mensajeros, turnos, asignaciones);
      const diff = r.tipo === "entrada" && horario ? minutosDeDiferencia(r.timestamp, horario.horaEntrada) : null;
      const dist = p ? haversine(r.lat, r.lng, p.lat, p.lng) : null;
      return {
        "Mensajero": r.mensajero,
        "Placa": r.placa || "",
        "Ciudad": mj?.ciudad || "",
        "Turno del día": horario?.turnoNombre || (horario ? "Horario base" : ""),
        "Tipo": r.tipo === "entrada" ? "Entrada" : "Salida",
        "Fecha": fmtFechaExport(r.timestamp),
        "Hora": fmtHora(r.timestamp),
        "Punto": p ? `${p.codigo} - ${p.nombre}` : "",
        "Latitud marcada": r.lat,
        "Longitud marcada": r.lng,
        "Latitud punto": p?.lat ?? "",
        "Longitud punto": p?.lng ?? "",
        "Distancia (m)": dist != null ? Math.round(dist) : "",
        "Fuera de zona (>150m)": dist != null ? (dist > 150 ? "Sí" : "No") : "",
        "Diferencia vs hora esperada (min)": diff != null ? diff : "",
        "Puntual": diff != null ? (diff > TOLERANCIA_MIN ? "Tarde" : "A tiempo") : "",
      };
    });

  const ws = XLSX.utils.json_to_sheet(filas);
  ws["!cols"] = [
    { wch: 18 }, { wch: 10 }, { wch: 12 }, { wch: 12 }, { wch: 9 }, { wch: 12 }, { wch: 10 }, { wch: 24 },
    { wch: 14 }, { wch: 14 }, { wch: 14 }, { wch: 14 }, { wch: 12 }, { wch: 14 }, { wch: 14 }, { wch: 12 },
  ];
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Gestión");
  const nombreArchivo = `gestion_nvo_${toDateKey(desde)}_a_${toDateKey(hasta)}.xlsx`;
  XLSX.writeFile(wb, nombreArchivo);
}

