function AsignacionManual({ mensajeros, turnos, asignaciones, onAsignar, onQuitar }) {
  const [busqueda, setBusqueda] = useState("");
  const [ciudadSel, setCiudadSel] = useState("todas");
  const [mensajeroSel, setMensajeroSel] = useState(null);
  const [fecha, setFecha] = useState(toDateKey(new Date()));
  const [turnoId, setTurnoId] = useState(turnos[0]?.id || "");

  const ciudadesConGente = CIUDADES.filter((c) => mensajeros.some((m) => m.ciudad === c));
  const LIMITE = 30;
  const resultadosTotal = mensajeros
    .filter((m) => ciudadSel === "todas" || m.ciudad === ciudadSel)
    .filter((m) => m.nombre.toLowerCase().includes(busqueda.toLowerCase()))
    .sort((a, b) => a.nombre.localeCompare(b.nombre));
  const resultados = resultadosTotal.slice(0, LIMITE);

  const asignacionesDelMensajero = mensajeroSel
    ? asignaciones.filter((a) => a.mensajero === mensajeroSel.nombre).sort((a, b) => b.fecha.localeCompare(a.fecha))
    : [];

  function asignar() {
    if (!mensajeroSel || !fecha || !turnoId) return;
    onAsignar({ mensajero: mensajeroSel.nombre, fecha, turnoId });
  }

  return (
    <div>
      <div style={{ marginBottom: 14 }}>
        <label style={{ fontSize: 11, fontWeight: 700, color: "var(--muted)", textTransform: "uppercase", letterSpacing: "0.05em" }}>Buscar mensajero</label>
        <input
          placeholder="Escribe un nombre…"
          value={mensajeroSel ? mensajeroSel.nombre : busqueda}
          onChange={(e) => { setBusqueda(e.target.value); setMensajeroSel(null); }}
          style={{ ...inputStyle(), width: "100%", marginTop: 4 }}
        />
        {!mensajeroSel && ciudadesConGente.length > 1 && (
          <div style={{ display: "flex", gap: 6, marginTop: 8, overflowX: "auto", paddingBottom: 2 }}>
            <button onClick={() => setCiudadSel("todas")} style={chipFiltroStyle(ciudadSel === "todas")}>Todas</button>
            {ciudadesConGente.map((c) => (
              <button key={c} onClick={() => setCiudadSel(c)} style={chipFiltroStyle(ciudadSel === c)}>{c}</button>
            ))}
          </div>
        )}
        {(busqueda || ciudadSel !== "todas") && !mensajeroSel && (
          <div style={{ border: "1px solid var(--line)", borderRadius: 8, marginTop: 8, overflow: "hidden", maxHeight: 280, overflowY: "auto" }}>
            {resultados.length === 0 && <div style={{ padding: 10, fontSize: 13, color: "var(--muted)" }}>Sin resultados.</div>}
            {resultados.map((m) => (
              <button
                key={m.nombre}
                onClick={() => { setMensajeroSel(m); setBusqueda(""); }}
                style={{ display: "block", width: "100%", textAlign: "left", padding: "10px 12px", border: "none", borderBottom: "1px solid var(--line)", background: "var(--paper)", fontSize: 13, cursor: "pointer", color: "var(--ink)" }}
              >
                {m.nombre} <span style={{ color: "var(--muted)", fontSize: 11 }}>· {m.ciudad}</span>
              </button>
            ))}
            {resultadosTotal.length > LIMITE && (
              <div style={{ padding: "8px 12px", fontSize: 11, color: "var(--muted)" }}>Hay {resultadosTotal.length - LIMITE} más — sigue escribiendo para afinar.</div>
            )}
          </div>
        )}
      </div>

      {mensajeroSel && (
        <>
          <div style={{ display: "flex", gap: 8, marginBottom: 10 }}>
            <div style={{ flex: 1 }}>
              <label style={{ fontSize: 11, fontWeight: 700, color: "var(--muted)" }}>Fecha</label>
              <input type="date" value={fecha} onChange={(e) => setFecha(e.target.value)} style={{ ...inputStyle(), width: "100%", marginTop: 4 }} />
            </div>
            <div style={{ flex: 1 }}>
              <label style={{ fontSize: 11, fontWeight: 700, color: "var(--muted)" }}>Turno</label>
              <select value={turnoId} onChange={(e) => setTurnoId(e.target.value)} style={{ ...inputStyle(), width: "100%", marginTop: 4 }}>
                {turnos.map((t) => <option key={t.id} value={t.id}>{t.nombre} ({t.horaEntrada}–{t.horaSalida})</option>)}
              </select>
            </div>
          </div>
          <button
            onClick={asignar}
            style={{ width: "100%", background: "var(--accent)", color: "white", border: "none", borderRadius: 8, padding: "11px", fontSize: 13, fontWeight: 700, cursor: "pointer", marginBottom: 16 }}
          >
            Asignar turno
          </button>

          <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: "0.05em", textTransform: "uppercase", color: "var(--muted)", marginBottom: 8 }}>
            Turnos asignados a {mensajeroSel.nombre}
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 6, maxHeight: 220, overflowY: "auto" }}>
            {asignacionesDelMensajero.length === 0 && <div style={{ fontSize: 13, color: "var(--muted)" }}>Sin turnos asignados todavía.</div>}
            {asignacionesDelMensajero.map((a, i) => {
              const t = turnos.find((tu) => tu.id === a.turnoId);
              return (
                <div key={i} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "8px 10px", border: "1px solid var(--line)", borderRadius: 8, background: "var(--paper)" }}>
                  <div style={{ fontSize: 12 }}>
                    <span style={{ fontWeight: 700, color: "var(--ink)" }}>{new Date(a.fecha + "T00:00:00").toLocaleDateString("es-CO", { day: "2-digit", month: "short" })}</span>
                    <span style={{ color: "var(--muted)" }}> · {t?.nombre || "—"} ({t?.horaEntrada}–{t?.horaSalida})</span>
                  </div>
                  <button onClick={() => onQuitar(mensajeroSel.nombre, a.fecha)} style={{ background: "none", border: "none", color: "var(--accent)", cursor: "pointer", display: "flex" }}>
                    <X size={14} />
                  </button>
                </div>
              );
            })}
          </div>
        </>
      )}
    </div>
  );
}

function CargaMasiva({ mensajeros, turnos, onImportar }) {
  const fileRef = useRef(null);
  const [estado, setEstado] = useState(null); // null | { ok, errores, total }
  const [procesando, setProcesando] = useState(false);

  function plantilla() {
    const filas = mensajeros.slice(0, 2).map((m) => ({ mensajero: m.nombre, fecha: toDateKey(new Date()), turno: turnos[0]?.nombre || "Mañana" }));
    const ws = XLSX.utils.json_to_sheet(filas);
    ws["!cols"] = [{ wch: 20 }, { wch: 14 }, { wch: 14 }];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Turnos");
    XLSX.writeFile(wb, "plantilla_turnos_nvo.xlsx");
  }

  function procesarArchivo(file) {
    setProcesando(true);
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const wb = XLSX.read(e.target.result, { type: "binary" });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const filas = XLSX.utils.sheet_to_json(ws, { raw: false });

        const validas = [];
        const errores = [];

        filas.forEach((fila, idx) => {
          const nombreMj = String(fila.mensajero || fila.Mensajero || "").trim();
          const fechaRaw = String(fila.fecha || fila.Fecha || "").trim();
          const nombreTurno = String(fila.turno || fila.Turno || "").trim();

          const mj = mensajeros.find((m) => m.nombre.toLowerCase() === nombreMj.toLowerCase());
          const turno = turnos.find((t) => t.nombre.toLowerCase() === nombreTurno.toLowerCase());

          let fechaKey = fechaRaw;
          // Si viene como fecha de Excel (serial) o formato dd/mm/yyyy, normalizar
          if (/^\d{1,2}\/\d{1,2}\/\d{2,4}$/.test(fechaRaw)) {
            const [d, m, y] = fechaRaw.split("/").map(Number);
            const year = y < 100 ? 2000 + y : y;
            fechaKey = `${year}-${String(m).padStart(2, "0")}-${String(d).padStart(2, "0")}`;
          }

          if (!mj) { errores.push({ fila: idx + 2, motivo: `Mensajero "${nombreMj}" no existe` }); return; }
          if (!turno) { errores.push({ fila: idx + 2, motivo: `Turno "${nombreTurno}" no existe` }); return; }
          if (!/^\d{4}-\d{2}-\d{2}$/.test(fechaKey)) { errores.push({ fila: idx + 2, motivo: `Fecha "${fechaRaw}" no es válida` }); return; }

          validas.push({ mensajero: mj.nombre, fecha: fechaKey, turnoId: turno.id });
        });

        if (validas.length > 0) onImportar(validas);
        setEstado({ ok: validas.length, errores, total: filas.length });
      } catch (err) {
        setEstado({ ok: 0, errores: [{ fila: "-", motivo: "No se pudo leer el archivo. Verifica que sea .xlsx o .csv válido." }], total: 0 });
      }
      setProcesando(false);
    };
    reader.readAsBinaryString(file);
  }

  return (
    <div>
      <div style={{ fontSize: 12, color: "var(--muted)", marginBottom: 12, lineHeight: 1.5 }}>
        Sube un archivo Excel o CSV con las columnas <b>mensajero</b>, <b>fecha</b> (AAAA-MM-DD) y <b>turno</b> (debe coincidir con el nombre exacto de un turno ya creado).
      </div>
      <button onClick={plantilla} style={{ display: "flex", alignItems: "center", gap: 6, background: "var(--bg)", border: "1px solid var(--line)", borderRadius: 8, padding: "9px 14px", fontSize: 12, fontWeight: 700, color: "var(--ink)", cursor: "pointer", marginBottom: 14 }}>
        <Download size={13} /> Descargar plantilla
      </button>

      <input
        ref={fileRef}
        type="file"
        accept=".xlsx,.xls,.csv"
        style={{ display: "none" }}
        onChange={(e) => { const f = e.target.files?.[0]; if (f) procesarArchivo(f); }}
      />
      <button
        onClick={() => fileRef.current?.click()}
        disabled={procesando}
        style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, background: "var(--accent)", color: "white", border: "none", borderRadius: 8, padding: "12px", fontSize: 13, fontWeight: 700, cursor: "pointer" }}
      >
        {procesando ? <Loader2 size={15} className="spin" /> : <Plus size={15} />}
        {procesando ? "Procesando…" : "Subir archivo de turnos"}
      </button>

      {estado && (
        <div style={{ marginTop: 14, border: "1px solid var(--line)", borderRadius: 10, padding: 12, background: "var(--bg)" }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: estado.ok > 0 ? "var(--ok)" : "var(--accent)", marginBottom: 4 }}>
            {estado.ok} de {estado.total} filas importadas correctamente
          </div>
          {estado.errores.length > 0 && (
            <div style={{ fontSize: 12, color: "var(--accent)" }}>
              {estado.errores.slice(0, 6).map((er, i) => (
                <div key={i}>Fila {er.fila}: {er.motivo}</div>
              ))}
              {estado.errores.length > 6 && <div>… y {estado.errores.length - 6} error(es) más.</div>}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function GestorTurnos({ mensajeros, turnos, asignaciones, onAddTurno, onAsignar, onQuitarAsignacion, onImportarMasivo }) {
  const [subtab, setSubtab] = useState("manual"); // manual | masiva | catalogo
  const [showNuevoTurno, setShowNuevoTurno] = useState(false);

  return (
    <div className="nvo-turnos-wrap" style={{ padding: 18 }}>
      <div style={{ display: "flex", gap: 6, marginBottom: 16 }}>
        {[["manual", "Asignar manual"], ["masiva", "Carga masiva"], ["catalogo", "Turnos"]].map(([k, label]) => (
          <button
            key={k}
            onClick={() => setSubtab(k)}
            style={{
              flex: 1, padding: "8px 6px", borderRadius: 8, fontSize: 11.5, fontWeight: 700,
              border: subtab === k ? "1px solid var(--ink)" : "1px solid var(--line)",
              background: subtab === k ? "var(--ink)" : "var(--paper)",
              color: subtab === k ? "var(--paper)" : "var(--muted)",
              cursor: "pointer",
            }}
          >
            {label}
          </button>
        ))}
      </div>

      {subtab === "manual" && (
        <AsignacionManual mensajeros={mensajeros} turnos={turnos} asignaciones={asignaciones} onAsignar={onAsignar} onQuitar={onQuitarAsignacion} />
      )}

      {subtab === "masiva" && (
        <CargaMasiva mensajeros={mensajeros} turnos={turnos} onImportar={onImportarMasivo} />
      )}

      {subtab === "catalogo" && (
        <div>
          <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 14 }}>
            {turnos.map((t) => (
              <div key={t.id} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "10px 12px", border: "1px solid var(--line)", borderRadius: 10, background: "var(--paper)" }}>
                <div>
                  <div style={{ fontSize: 13, fontWeight: 700, color: "var(--ink)" }}>{t.nombre}</div>
                  <div style={{ fontSize: 11, color: "var(--muted)" }}>{t.horaEntrada} — {t.horaSalida}</div>
                </div>
                {t.predefinido && <span style={{ fontSize: 10, fontWeight: 700, color: "var(--muted)", background: "var(--bg)", padding: "2px 8px", borderRadius: 20 }}>Predefinido</span>}
              </div>
            ))}
          </div>
          <button
            onClick={() => setShowNuevoTurno(true)}
            style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "center", gap: 6, background: "var(--ink)", color: "var(--paper)", border: "none", borderRadius: 8, padding: "11px", fontSize: 13, fontWeight: 700, cursor: "pointer" }}
          >
            <Plus size={14} /> Crear turno personalizado
          </button>
        </div>
      )}

      {showNuevoTurno && (
        <ModalTurnoPersonalizado
          onClose={() => setShowNuevoTurno(false)}
          onSave={(turno) => { onAddTurno(turno); setShowNuevoTurno(false); }}
        />
      )}
    </div>
  );
}


// ---------- Gestor de conductores (crear manual y masivo) ----------
function GestorConductores({ mensajeros, onAddConductor, onDeleteConductor, onImportarConductores }) {
  const [subtab, setSubtab] = useState("lista"); // lista | manual | masiva
  const [nombre, setNombre] = useState("");
  const [placa, setPlaca] = useState("");
  const [ciudad, setCiudad] = useState(CIUDADES[0]);
  const [horaEntrada, setHoraEntrada] = useState("08:00");
  const [horaSalida, setHoraSalida] = useState("18:00");
  const [error, setError] = useState("");
  const [exito, setExito] = useState("");
  const [busqueda, setBusqueda] = useState("");
  const [ciudadFiltro, setCiudadFiltro] = useState("todas");

  // ── Manual ──
  function crearManual() {
    const nombreLimpio = nombre.trim();
    const placaLimpia = placa.trim().toUpperCase();
    if (!nombreLimpio) { setError("El nombre es obligatorio."); return; }
    if (!placaLimpia) { setError("La placa es obligatoria."); return; }
    if (mensajeros.some((m) => m.nombre.toLowerCase() === nombreLimpio.toLowerCase())) {
      setError(`Ya existe un conductor con el nombre "${nombreLimpio}".`);
      return;
    }
    setError("");
    onAddConductor({ nombre: nombreLimpio, placa: placaLimpia, ciudad, horaEntrada, horaSalida });
    setNombre(""); setPlaca("");
    setExito(`${nombreLimpio} creado correctamente.`);
    setTimeout(() => setExito(""), 3000);
  }

  // ── Masiva ──
  const fileRef = useRef(null);
  const [procesando, setProcesando] = useState(false);
  const [resultadoCarga, setResultadoCarga] = useState(null);

  function plantillaConductores() {
    const filas = [
      { nombre: "Juan Pérez", placa: "ABC123", ciudad: "Bogotá", horaEntrada: "08:00", horaSalida: "18:00" },
      { nombre: "María López", placa: "XYZ789", ciudad: "Medellín", horaEntrada: "07:30", horaSalida: "17:30" },
    ];
    const ws = XLSX.utils.json_to_sheet(filas);
    ws["!cols"] = [{ wch: 22 }, { wch: 10 }, { wch: 14 }, { wch: 12 }, { wch: 12 }];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Conductores");
    XLSX.writeFile(wb, "plantilla_conductores_nvo.xlsx");
  }

  function procesarArchivoConductores(file) {
    setProcesando(true);
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const wb = XLSX.read(e.target.result, { type: "binary" });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const filas = XLSX.utils.sheet_to_json(ws, { raw: false });

        const validas = [];
        const errores = [];
        const nombresExistentes = new Set(mensajeros.map((m) => m.nombre.toLowerCase()));

        filas.forEach((fila, idx) => {
          const n = String(fila.nombre || fila.Nombre || "").trim();
          const p = String(fila.placa || fila.Placa || "").trim().toUpperCase();
          const c = String(fila.ciudad || fila.Ciudad || "").trim();
          const he = String(fila.horaEntrada || fila["Hora Entrada"] || fila.hora_entrada || "08:00").trim();
          const hs = String(fila.horaSalida || fila["Hora Salida"] || fila.hora_salida || "18:00").trim();

          if (!n) { errores.push({ fila: idx + 2, motivo: "Nombre vacío" }); return; }
          if (!p) { errores.push({ fila: idx + 2, motivo: `Placa vacía para "${n}"` }); return; }
          if (!c) { errores.push({ fila: idx + 2, motivo: `Ciudad vacía para "${n}"` }); return; }
          if (!CIUDADES.includes(c)) { errores.push({ fila: idx + 2, motivo: `Ciudad "${c}" no válida para "${n}"` }); return; }
          if (nombresExistentes.has(n.toLowerCase())) { errores.push({ fila: idx + 2, motivo: `"${n}" ya existe` }); return; }

          nombresExistentes.add(n.toLowerCase());
          validas.push({ nombre: n, placa: p, ciudad: c, horaEntrada: he, horaSalida: hs });
        });

        if (validas.length > 0) onImportarConductores(validas);
        setResultadoCarga({ ok: validas.length, errores, total: filas.length });
      } catch (err) {
        setResultadoCarga({ ok: 0, errores: [{ fila: "-", motivo: "No se pudo leer el archivo." }], total: 0 });
      }
      setProcesando(false);
    };
    reader.readAsBinaryString(file);
  }

  // ── Lista filtrada ──
  const ciudadesConGente = CIUDADES.filter((c) => mensajeros.some((m) => m.ciudad === c));
  const filtrados = mensajeros
    .filter((m) => ciudadFiltro === "todas" || m.ciudad === ciudadFiltro)
    .filter((m) => m.nombre.toLowerCase().includes(busqueda.toLowerCase()) || (m.placa || "").toLowerCase().includes(busqueda.toLowerCase()))
    .sort((a, b) => a.nombre.localeCompare(b.nombre));

  return (
    <div className="nvo-turnos-wrap" style={{ padding: 18 }}>
      <div style={{ display: "flex", gap: 6, marginBottom: 16 }}>
        {[["lista", "Conductores"], ["manual", "Crear manual"], ["masiva", "Carga masiva"]].map(([k, label]) => (
          <button
            key={k}
            onClick={() => setSubtab(k)}
            style={{
              flex: 1, padding: "8px 6px", borderRadius: 8, fontSize: 11.5, fontWeight: 700,
              border: subtab === k ? "1px solid var(--ink)" : "1px solid var(--line)",
              background: subtab === k ? "var(--ink)" : "var(--paper)",
              color: subtab === k ? "var(--paper)" : "var(--muted)",
              cursor: "pointer",
            }}
          >
            {label}
          </button>
        ))}
      </div>

      {/* ── LISTA ── */}
      {subtab === "lista" && (
        <div>
          <input
            placeholder="Buscar por nombre o placa…"
            value={busqueda}
            onChange={(e) => setBusqueda(e.target.value)}
            style={{ ...inputStyle(), width: "100%", marginBottom: 10 }}
          />
          {ciudadesConGente.length > 1 && (
            <div style={{ display: "flex", gap: 6, marginBottom: 12, overflowX: "auto", paddingBottom: 2 }}>
              <button onClick={() => setCiudadFiltro("todas")} style={chipFiltroStyle(ciudadFiltro === "todas")}>Todas</button>
              {ciudadesConGente.map((c) => (
                <button key={c} onClick={() => setCiudadFiltro(c)} style={chipFiltroStyle(ciudadFiltro === c)}>{c}</button>
              ))}
            </div>
          )}
          <div style={{ fontSize: 11, color: "var(--muted)", marginBottom: 8 }}>
            {filtrados.length} conductor{filtrados.length !== 1 ? "es" : ""}
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 6, maxHeight: 400, overflowY: "auto" }}>
            {filtrados.length === 0 && <div style={{ fontSize: 13, color: "var(--muted)" }}>Sin resultados.</div>}
            {filtrados.map((mj) => (
              <div key={mj.nombre} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "10px 12px", border: "1px solid var(--line)", borderRadius: 10, background: "var(--paper)" }}>
                <div>
                  <div style={{ fontSize: 13, fontWeight: 700, color: "var(--ink)" }}>{mj.nombre}</div>
                  <div style={{ fontSize: 11, color: "var(--muted)" }}>
                    {mj.placa ? `${mj.placa} · ` : ""}{mj.ciudad} · {mj.horaEntrada}–{mj.horaSalida}
                  </div>
                </div>
                <button
                  onClick={() => { if (window.confirm(`¿Eliminar a ${mj.nombre}?`)) onDeleteConductor(mj.nombre); }}
                  style={{ background: "none", border: "none", color: "var(--accent)", cursor: "pointer", display: "flex", padding: 4 }}
                  title="Eliminar conductor"
                >
                  <Trash2 size={15} />
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ── MANUAL ── */}
      {subtab === "manual" && (
        <div>
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            <div>
              <label style={{ fontSize: 11, fontWeight: 700, color: "var(--muted)", textTransform: "uppercase", letterSpacing: "0.05em" }}>Nombre completo *</label>
              <input placeholder="Ej. Carlos Ramírez" value={nombre} onChange={(e) => setNombre(e.target.value)} style={{ ...inputStyle(), width: "100%", marginTop: 4 }} />
            </div>
            <div style={{ display: "flex", gap: 8 }}>
              <div style={{ flex: 1 }}>
                <label style={{ fontSize: 11, fontWeight: 700, color: "var(--muted)", textTransform: "uppercase", letterSpacing: "0.05em" }}>Placa *</label>
                <input placeholder="ABC123" value={placa} onChange={(e) => setPlaca(e.target.value.toUpperCase())} style={{ ...inputStyle(), width: "100%", marginTop: 4, fontFamily: "monospace" }} />
              </div>
              <div style={{ flex: 1 }}>
                <label style={{ fontSize: 11, fontWeight: 700, color: "var(--muted)", textTransform: "uppercase", letterSpacing: "0.05em" }}>Ciudad *</label>
                <select value={ciudad} onChange={(e) => setCiudad(e.target.value)} style={{ ...inputStyle(), width: "100%", marginTop: 4 }}>
                  {CIUDADES.map((c) => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
            </div>
            <div style={{ display: "flex", gap: 8 }}>
              <div style={{ flex: 1 }}>
                <label style={{ fontSize: 11, fontWeight: 700, color: "var(--muted)", textTransform: "uppercase", letterSpacing: "0.05em" }}>Hora entrada</label>
                <input type="time" value={horaEntrada} onChange={(e) => setHoraEntrada(e.target.value)} style={{ ...inputStyle(), width: "100%", marginTop: 4 }} />
              </div>
              <div style={{ flex: 1 }}>
                <label style={{ fontSize: 11, fontWeight: 700, color: "var(--muted)", textTransform: "uppercase", letterSpacing: "0.05em" }}>Hora salida</label>
                <input type="time" value={horaSalida} onChange={(e) => setHoraSalida(e.target.value)} style={{ ...inputStyle(), width: "100%", marginTop: 4 }} />
              </div>
            </div>
            {error && (
              <div style={{ fontSize: 12, color: "var(--accent)", display: "flex", alignItems: "center", gap: 6 }}>
                <AlertTriangle size={13} /> {error}
              </div>
            )}
            {exito && (
              <div style={{ fontSize: 12, color: "var(--ok)", display: "flex", alignItems: "center", gap: 6 }}>
                <Check size={13} /> {exito}
              </div>
            )}
            <button
              onClick={crearManual}
              style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, background: "var(--accent)", color: "white", border: "none", borderRadius: 8, padding: "12px", fontSize: 13, fontWeight: 700, cursor: "pointer", marginTop: 4 }}
            >
              <Plus size={15} /> Crear conductor
            </button>
          </div>
        </div>
      )}

      {/* ── MASIVA ── */}
      {subtab === "masiva" && (
        <div>
          <div style={{ fontSize: 12, color: "var(--muted)", marginBottom: 12, lineHeight: 1.5 }}>
            Sube un archivo Excel o CSV con las columnas <b>nombre</b>, <b>placa</b> y <b>ciudad</b>.
            Opcionalmente puedes incluir <b>horaEntrada</b> y <b>horaSalida</b> (por defecto 08:00–18:00).
          </div>
          <div style={{ fontSize: 11, color: "var(--muted)", marginBottom: 12 }}>
            <b>Ciudades válidas:</b> {CIUDADES.join(", ")}
          </div>
          <button onClick={plantillaConductores} style={{ display: "flex", alignItems: "center", gap: 6, background: "var(--bg)", border: "1px solid var(--line)", borderRadius: 8, padding: "9px 14px", fontSize: 12, fontWeight: 700, color: "var(--ink)", cursor: "pointer", marginBottom: 14 }}>
            <Download size={13} /> Descargar plantilla
          </button>

          <input
            ref={fileRef}
            type="file"
            accept=".xlsx,.xls,.csv"
            style={{ display: "none" }}
            onChange={(e) => { const f = e.target.files?.[0]; if (f) procesarArchivoConductores(f); }}
          />
          <button
            onClick={() => fileRef.current?.click()}
            disabled={procesando}
            style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, background: "var(--accent)", color: "white", border: "none", borderRadius: 8, padding: "12px", fontSize: 13, fontWeight: 700, cursor: "pointer" }}
          >
            {procesando ? <Loader2 size={15} className="spin" /> : <Upload size={15} />}
            {procesando ? "Procesando…" : "Subir archivo de conductores"}
          </button>

          {resultadoCarga && (
            <div style={{ marginTop: 14, border: "1px solid var(--line)", borderRadius: 10, padding: 12, background: "var(--bg)" }}>
              <div style={{ fontSize: 13, fontWeight: 700, color: resultadoCarga.ok > 0 ? "var(--ok)" : "var(--accent)", marginBottom: 4 }}>
                {resultadoCarga.ok} de {resultadoCarga.total} conductores importados
              </div>
              {resultadoCarga.errores.length > 0 && (
                <div style={{ fontSize: 12, color: "var(--accent)" }}>
                  {resultadoCarga.errores.slice(0, 8).map((er, i) => (
                    <div key={i}>Fila {er.fila}: {er.motivo}</div>
                  ))}
                  {resultadoCarga.errores.length > 8 && <div>… y {resultadoCarga.errores.length - 8} error(es) más.</div>}
                </div>
              )}
            </div>
          )}
        </div>
      )}
    </div>
  );
}


// ---------- Combo buscable (para listas largas de mensajeros) ----------
function ComboBuscable({ mensajeros, valor, onChange, placeholder = "Todos los mensajeros", etiquetaTodos }) {
  const [abierto, setAbierto] = useState(false);
  const [busqueda, setBusqueda] = useState("");
  const wrapRef = useRef(null);

  useEffect(() => {
    function onClickFuera(e) {
      if (wrapRef.current && !wrapRef.current.contains(e.target)) setAbierto(false);
    }
    document.addEventListener("mousedown", onClickFuera);
    return () => document.removeEventListener("mousedown", onClickFuera);
  }, []);

  const filtrados = mensajeros
    .filter((m) => m.nombre.toLowerCase().includes(busqueda.toLowerCase()))
    .sort((a, b) => a.nombre.localeCompare(b.nombre))
    .slice(0, 40);

  const seleccionado = mensajeros.find((m) => m.nombre === valor);
  const etiquetaActual = valor === "todos" || !valor ? (etiquetaTodos || placeholder) : (seleccionado?.nombre || valor);

  return (
    <div ref={wrapRef} style={{ position: "relative", width: "100%" }}>
      <button
        onClick={() => setAbierto(!abierto)}
        style={{ ...selStyle(), width: "100%", textAlign: "left", display: "flex", alignItems: "center", justifyContent: "space-between", cursor: "pointer" }}
      >
        <span style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{etiquetaActual}</span>
        <ChevronRight size={14} style={{ transform: abierto ? "rotate(90deg)" : "rotate(0deg)", transition: "transform 0.15s", flexShrink: 0, marginLeft: 6 }} />
      </button>
      {abierto && (
        <div style={{ position: "absolute", top: "calc(100% + 4px)", left: 0, right: 0, background: "var(--paper)", border: "1px solid var(--line)", borderRadius: 10, boxShadow: "0 8px 24px rgba(14,42,82,0.15)", zIndex: 50, maxHeight: 320, display: "flex", flexDirection: "column" }}>
          <input
            autoFocus
            placeholder="Buscar mensajero…"
            value={busqueda}
            onChange={(e) => setBusqueda(e.target.value)}
            style={{ border: "none", borderBottom: "1px solid var(--line)", padding: "10px 12px", fontSize: 13, outline: "none", fontFamily: "var(--font-body)" }}
          />
          <div style={{ overflowY: "auto" }}>
            <button
              onClick={() => { onChange("todos"); setAbierto(false); setBusqueda(""); }}
              style={{ display: "block", width: "100%", textAlign: "left", padding: "9px 12px", border: "none", background: valor === "todos" ? "var(--accent-soft)" : "var(--paper)", fontSize: 13, cursor: "pointer", color: "var(--ink)", fontWeight: 700 }}
            >
              {etiquetaTodos || placeholder}
            </button>
            {filtrados.map((m) => (
              <button
                key={m.nombre}
                onClick={() => { onChange(m.nombre); setAbierto(false); setBusqueda(""); }}
                style={{ display: "block", width: "100%", textAlign: "left", padding: "9px 12px", border: "none", borderTop: "1px solid var(--line)", background: valor === m.nombre ? "var(--accent-soft)" : "var(--paper)", fontSize: 13, cursor: "pointer", color: "var(--ink)" }}
              >
                {m.nombre} <span style={{ color: "var(--muted)", fontSize: 11 }}>· {m.ciudad}</span>
              </button>
            ))}
            {filtrados.length === 0 && <div style={{ padding: "12px", fontSize: 12, color: "var(--muted)" }}>Sin resultados.</div>}
            {mensajeros.length > 40 && filtrados.length === 40 && (
              <div style={{ padding: "8px 12px", fontSize: 11, color: "var(--muted)", borderTop: "1px solid var(--line)" }}>Sigue escribiendo para afinar la búsqueda.</div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}


// ---------- Combo buscable de tiendas (código + nombre + dirección) ----------
function ComboBuscableTienda({ puntos, valor, onChange }) {
  const [abierto, setAbierto] = useState(false);
  const [busqueda, setBusqueda] = useState("");
  const wrapRef = useRef(null);

  useEffect(() => {
    function onClickFuera(e) {
      if (wrapRef.current && !wrapRef.current.contains(e.target)) setAbierto(false);
    }
    document.addEventListener("mousedown", onClickFuera);
    return () => document.removeEventListener("mousedown", onClickFuera);
  }, []);

  const q = busqueda.toLowerCase();
  const filtrados = puntos
    .filter((p) => p.codigo.toLowerCase().includes(q) || p.nombre.toLowerCase().includes(q) || p.direccion.toLowerCase().includes(q))
    .sort((a, b) => a.nombre.localeCompare(b.nombre))
    .slice(0, 40);

  const seleccionado = puntos.find((p) => p.id === valor);
  const etiquetaActual = valor === "todas" || !valor ? "Todas las tiendas" : (seleccionado ? `${seleccionado.codigo} · ${seleccionado.nombre}` : "Todas las tiendas");

  return (
    <div ref={wrapRef} style={{ position: "relative", width: "100%" }}>
      <button
        onClick={() => setAbierto(!abierto)}
        style={{ ...selStyle(), width: "100%", textAlign: "left", display: "flex", alignItems: "center", justifyContent: "space-between", cursor: "pointer" }}
      >
        <span style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{etiquetaActual}</span>
        <ChevronRight size={14} style={{ transform: abierto ? "rotate(90deg)" : "rotate(0deg)", transition: "transform 0.15s", flexShrink: 0, marginLeft: 6 }} />
      </button>
      {abierto && (
        <div style={{ position: "absolute", top: "calc(100% + 4px)", left: 0, right: 0, background: "var(--paper)", border: "1px solid var(--line)", borderRadius: 10, boxShadow: "0 8px 24px rgba(14,42,82,0.15)", zIndex: 50, maxHeight: 340, display: "flex", flexDirection: "column" }}>
          <input
            autoFocus
            placeholder="Buscar por código, nombre o dirección…"
            value={busqueda}
            onChange={(e) => setBusqueda(e.target.value)}
            style={{ border: "none", borderBottom: "1px solid var(--line)", padding: "10px 12px", fontSize: 13, outline: "none", fontFamily: "var(--font-body)" }}
          />
          <div style={{ overflowY: "auto" }}>
            <button
              onClick={() => { onChange("todas"); setAbierto(false); setBusqueda(""); }}
              style={{ display: "block", width: "100%", textAlign: "left", padding: "9px 12px", border: "none", background: valor === "todas" ? "var(--accent-soft)" : "var(--paper)", fontSize: 13, cursor: "pointer", color: "var(--ink)", fontWeight: 700 }}
            >
              Todas las tiendas
            </button>
            {filtrados.map((p) => (
              <button
                key={p.id}
                onClick={() => { onChange(p.id); setAbierto(false); setBusqueda(""); }}
                style={{ display: "block", width: "100%", textAlign: "left", padding: "9px 12px", border: "none", borderTop: "1px solid var(--line)", background: valor === p.id ? "var(--accent-soft)" : "var(--paper)", fontSize: 13, cursor: "pointer", color: "var(--ink)" }}
              >
                <span style={{ fontWeight: 700 }}>{p.codigo}</span> · {p.nombre}
                <div style={{ fontSize: 11, color: "var(--muted)", marginTop: 1 }}>{p.direccion} · {p.ciudad}</div>
              </button>
            ))}
            {filtrados.length === 0 && <div style={{ padding: "12px", fontSize: 12, color: "var(--muted)" }}>Sin resultados.</div>}
            {puntos.length > 40 && filtrados.length === 40 && (
              <div style={{ padding: "8px 12px", fontSize: 11, color: "var(--muted)", borderTop: "1px solid var(--line)" }}>Sigue escribiendo para afinar la búsqueda.</div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

// ---------- Vista: panel administrador ----------
function PanelAdmin({ puntos, registros, mensajeros, turnos, asignaciones, onAddPunto, onUpdateMensajero, onAddConductor, onDeleteConductor, onImportarConductores, onAddTurno, onAsignarTurno, onQuitarAsignacion, onImportarMasivo, onBack }) {
  const [tab, setTab] = useState("bitacora"); // bitacora | dashboard | equipo | turnos
  const [fechaSeleccionada, setFechaSeleccionada] = useState(new Date());
  const [filtroMensajero, setFiltroMensajero] = useState("todos");
  const [filtroCiudad, setFiltroCiudad] = useState("todas");
  const [filtroTienda, setFiltroTienda] = useState("todas");
  const [usarFecha, setUsarFecha] = useState(true);
  const [seleccion, setSeleccion] = useState(null);
  const [showNuevoPunto, setShowNuevoPunto] = useState(false);
  const [showExportar, setShowExportar] = useState(false);
  const [editandoHorario, setEditandoHorario] = useState(null);
  const [ampliarFoto, setAmpliarFoto] = useState(false);
  const [ampliarMapa, setAmpliarMapa] = useState(false);
  const [busquedaEquipo, setBusquedaEquipo] = useState("");
  const [ciudadEquipo, setCiudadEquipo] = useState("todas");
  const [nuevoPunto, setNuevoPunto] = useState({ codigo: "", nombre: "", ciudad: CIUDADES[0], coordenadas: "", direccion: "" });

  const mensajerosFiltrados = filtroCiudad === "todas" ? mensajeros : mensajeros.filter((m) => m.ciudad === filtroCiudad);
  const puntosFiltrados = filtroCiudad === "todas" ? puntos : puntos.filter((p) => p.ciudad === filtroCiudad);

  const conteoPorDia = registros.reduce((acc, r) => {
    const k = toDateKey(r.timestamp);
    acc[k] = (acc[k] || 0) + 1;
    return acc;
  }, {});

  const lista = registros
    .filter((r) => filtroMensajero === "todos" || r.mensajero === filtroMensajero)
    .filter((r) => filtroCiudad === "todas" || mensajeros.find((m) => m.nombre === r.mensajero)?.ciudad === filtroCiudad)
    .filter((r) => filtroTienda === "todas" || r.puntoId === filtroTienda)
    .filter((r) => !usarFecha || toDateKey(r.timestamp) === toDateKey(fechaSeleccionada))
    .sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));

  const activo = seleccion || lista[0];
  const puntoActivo = activo ? puntos.find((p) => p.id === activo.puntoId) : null;
  const distancia = activo && puntoActivo ? haversine(activo.lat, activo.lng, puntoActivo.lat, puntoActivo.lng) : null;
  const UMBRAL = 150; // metros tolerados

  function cambiarCiudad(c) {
    setFiltroCiudad(c);
    setFiltroMensajero("todos");
    setFiltroTienda("todas");
  }

  function irAHoy() {
    setFechaSeleccionada(new Date());
    setUsarFecha(true);
  }

  async function guardarPunto() {
    const coords = parsearCoordenadas(nuevoPunto.coordenadas);
    if (!nuevoPunto.codigo || !nuevoPunto.nombre || !coords) return;
    await onAddPunto({
      id: uid(),
      codigo: nuevoPunto.codigo,
      nombre: nuevoPunto.nombre,
      ciudad: nuevoPunto.ciudad,
      lat: coords.lat,
      lng: coords.lng,
      direccion: nuevoPunto.direccion,
    });
    setNuevoPunto({ codigo: "", nombre: "", ciudad: CIUDADES[0], coordenadas: "", direccion: "" });
    setShowNuevoPunto(false);
  }

  return (
    <div style={{ minHeight: "100%", display: "flex", flexDirection: "column" }}>
      <div style={{ padding: "16px 18px 14px", borderBottom: "1px solid var(--line)", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <button onClick={onBack} style={{ background: "none", border: "none", cursor: "pointer", color: "var(--muted)", display: "flex" }}>
            <ArrowLeft size={18} />
          </button>
          <img src={LOGO_SRC} alt="NVO" style={{ width: "auto", height: 26, objectFit: "contain" }} />
          <div>
            <div style={{ fontSize: 11, color: "var(--muted)", letterSpacing: "0.08em", textTransform: "uppercase", fontFamily: "var(--font-display)" }}>Panel</div>
            <div style={{ fontSize: 16, fontWeight: 700, color: "var(--ink)" }}>Control de gestión</div>
          </div>
        </div>
        <button onClick={() => setShowExportar(true)} style={{ display: "flex", alignItems: "center", gap: 6, background: "var(--accent)", color: "white", border: "none", borderRadius: 8, padding: "8px 12px", fontSize: 12, fontWeight: 700, cursor: "pointer" }}>
          <Download size={14} /> Exportar
        </button>
      </div>

      <div style={{ display: "flex", borderBottom: "1px solid var(--line)", overflowX: "auto" }}>
        <button
          onClick={() => setTab("bitacora")}
          style={{
            flex: "1 0 auto", minWidth: 90, padding: "12px 8px", fontSize: 12.5, fontWeight: 700, cursor: "pointer", border: "none",
            background: "transparent", color: tab === "bitacora" ? "var(--ink)" : "var(--muted)",
            borderBottom: tab === "bitacora" ? "2px solid var(--accent)" : "2px solid transparent",
            display: "flex", alignItems: "center", justifyContent: "center", gap: 5,
          }}
        >
          <List size={14} /> Bitácora
        </button>
        <button
          onClick={() => setTab("dashboard")}
          style={{
            flex: "1 0 auto", minWidth: 90, padding: "12px 8px", fontSize: 12.5, fontWeight: 700, cursor: "pointer", border: "none",
            background: "transparent", color: tab === "dashboard" ? "var(--ink)" : "var(--muted)",
            borderBottom: tab === "dashboard" ? "2px solid var(--accent)" : "2px solid transparent",
            display: "flex", alignItems: "center", justifyContent: "center", gap: 5,
          }}
        >
          <BarChart3 size={14} /> Dashboard
        </button>
        <button
          onClick={() => setTab("turnos")}
          style={{
            flex: "1 0 auto", minWidth: 90, padding: "12px 8px", fontSize: 12.5, fontWeight: 700, cursor: "pointer", border: "none",
            background: "transparent", color: tab === "turnos" ? "var(--ink)" : "var(--muted)",
            borderBottom: tab === "turnos" ? "2px solid var(--accent)" : "2px solid transparent",
            display: "flex", alignItems: "center", justifyContent: "center", gap: 5,
          }}
        >
          <Calendar size={14} /> Turnos
        </button>
        <button
          onClick={() => setTab("equipo")}
          style={{
            flex: "1 0 auto", minWidth: 90, padding: "12px 8px", fontSize: 12.5, fontWeight: 700, cursor: "pointer", border: "none",
            background: "transparent", color: tab === "equipo" ? "var(--ink)" : "var(--muted)",
            borderBottom: tab === "equipo" ? "2px solid var(--accent)" : "2px solid transparent",
            display: "flex", alignItems: "center", justifyContent: "center", gap: 5,
          }}
        >
          <Clock size={14} /> Horarios
        </button>
        <button
          onClick={() => setTab("conductores")}
          style={{
            flex: "1 0 auto", minWidth: 90, padding: "12px 8px", fontSize: 12.5, fontWeight: 700, cursor: "pointer", border: "none",
            background: "transparent", color: tab === "conductores" ? "var(--ink)" : "var(--muted)",
            borderBottom: tab === "conductores" ? "2px solid var(--accent)" : "2px solid transparent",
            display: "flex", alignItems: "center", justifyContent: "center", gap: 5,
          }}
        >
          <Users size={14} /> Conductores
        </button>
      </div>

      {tab === "dashboard" && (
        <Dashboard registros={registros} mensajeros={mensajeros} puntos={puntos} turnos={turnos} asignaciones={asignaciones} filtroCiudad={filtroCiudad} />
      )}

      {tab === "turnos" && (
        <GestorTurnos
          mensajeros={mensajeros}
          turnos={turnos}
          asignaciones={asignaciones}
          onAddTurno={onAddTurno}
          onAsignar={onAsignarTurno}
          onQuitarAsignacion={onQuitarAsignacion}
          onImportarMasivo={onImportarMasivo}
        />
      )}

      {tab === "equipo" && (
        <div style={{ padding: 18 }}>
          <div style={{ fontSize: 12, color: "var(--muted)", marginBottom: 14 }}>
            Define la hora esperada de entrada y salida de cada mensajero. Se usa para calcular puntualidad.
          </div>
          <input
            placeholder="Buscar mensajero…"
            value={busquedaEquipo}
            onChange={(e) => setBusquedaEquipo(e.target.value)}
            style={{ ...inputStyle(), width: "100%", marginBottom: 10 }}
          />
          {CIUDADES.filter((c) => mensajeros.some((m) => m.ciudad === c)).length > 1 && (
            <div style={{ display: "flex", gap: 6, marginBottom: 12, overflowX: "auto", paddingBottom: 2 }}>
              <button onClick={() => setCiudadEquipo("todas")} style={chipFiltroStyle(ciudadEquipo === "todas")}>Todas</button>
              {CIUDADES.filter((c) => mensajeros.some((m) => m.ciudad === c)).map((c) => (
                <button key={c} onClick={() => setCiudadEquipo(c)} style={chipFiltroStyle(ciudadEquipo === c)}>{c}</button>
              ))}
            </div>
          )}
          {(() => {
            const filtradosEquipo = mensajeros
              .filter((m) => ciudadEquipo === "todas" || m.ciudad === ciudadEquipo)
              .filter((m) => m.nombre.toLowerCase().includes(busquedaEquipo.toLowerCase()))
              .sort((a, b) => a.nombre.localeCompare(b.nombre));
            const LIMITE = 25;
            const visiblesEquipo = filtradosEquipo.slice(0, LIMITE);
            return (
              <>
                <div style={{ fontSize: 11, color: "var(--muted)", marginBottom: 8 }}>
                  {filtradosEquipo.length} mensajero{filtradosEquipo.length !== 1 ? "s" : ""}
                </div>
                <div className="nvo-horarios-grid" style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                  {visiblesEquipo.length === 0 && <div style={{ fontSize: 13, color: "var(--muted)" }}>Sin resultados.</div>}
                  {visiblesEquipo.map((mj) => (
                    <div key={mj.nombre} className="nvo-horario-card" style={{ border: "1px solid var(--line)", borderRadius: 10, padding: 12, background: "var(--paper)" }}>
                      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: editandoHorario === mj.nombre ? 10 : 0 }}>
                        <div>
                          <div style={{ fontSize: 13, fontWeight: 700, color: "var(--ink)" }}>{mj.nombre}</div>
                          <div style={{ fontSize: 11, color: "var(--muted)" }}>{mj.ciudad} · Entrada {mj.horaEntrada} · Salida {mj.horaSalida}</div>
                        </div>
                        <button
                          onClick={() => setEditandoHorario(editandoHorario === mj.nombre ? null : mj.nombre)}
                          style={iconBtnStyle()}
                        >
                          <Edit2 size={14} />
                        </button>
                      </div>
                      {editandoHorario === mj.nombre && (
                        <div style={{ display: "flex", gap: 8, marginTop: 8 }}>
                          <div style={{ flex: 1 }}>
                            <label style={{ fontSize: 10, color: "var(--muted)", fontWeight: 700 }}>Hora entrada</label>
                            <input type="time" value={mj.horaEntrada} onChange={(e) => onUpdateMensajero(mj.nombre, { horaEntrada: e.target.value })} style={{ ...inputStyle(), width: "100%", marginTop: 4 }} />
                          </div>
                          <div style={{ flex: 1 }}>
                            <label style={{ fontSize: 10, color: "var(--muted)", fontWeight: 700 }}>Hora salida</label>
                            <input type="time" value={mj.horaSalida} onChange={(e) => onUpdateMensajero(mj.nombre, { horaSalida: e.target.value })} style={{ ...inputStyle(), width: "100%", marginTop: 4 }} />
                          </div>
                        </div>
                      )}
                    </div>
                  ))}
                  {filtradosEquipo.length > LIMITE && (
                    <div style={{ textAlign: "center", padding: "8px 0", color: "var(--muted)", fontSize: 12 }}>
                      Hay {filtradosEquipo.length - LIMITE} más — afina la búsqueda para verlos.
                    </div>
                  )}
                </div>
              </>
            );
          })()}
        </div>
      )}

      {tab === "conductores" && (
        <GestorConductores
          mensajeros={mensajeros}
          onAddConductor={onAddConductor}
          onDeleteConductor={onDeleteConductor}
          onImportarConductores={onImportarConductores}
        />
      )}

      {tab === "bitacora" && (
        <>
          <div className="nvo-filtros-bitacora">
            <div style={{ padding: "14px 18px 0", display: "flex", gap: 8 }}>
              <select value={filtroCiudad} onChange={(e) => cambiarCiudad(e.target.value)} style={selStyle()}>
                <option value="todas">Todas las ciudades</option>
                {CIUDADES.map((c) => <option key={c} value={c}>{c}</option>)}
              </select>
              <button
                onClick={() => setShowNuevoPunto(true)}
                style={{ display: "flex", alignItems: "center", gap: 6, background: "var(--bg)", border: "1px solid var(--line)", borderRadius: 8, padding: "0 12px", fontSize: 12, fontWeight: 700, cursor: "pointer", color: "var(--ink)" }}
              >
                <Plus size={14} /> Punto
              </button>
            </div>
            <div style={{ padding: "8px 18px 14px" }}>
              <ComboBuscable
                mensajeros={mensajerosFiltrados}
                valor={filtroMensajero}
                onChange={setFiltroMensajero}
                etiquetaTodos={`Todos los mensajeros${filtroCiudad !== "todas" ? ` (${filtroCiudad})` : ""}`}
              />
            </div>
            <div style={{ padding: "0 18px 14px" }}>
              <ComboBuscableTienda
                puntos={puntosFiltrados}
                valor={filtroTienda}
                onChange={setFiltroTienda}
              />
            </div>
          </div>

          <div className="nvo-calendar-row" style={{ padding: "0 18px 14px" }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 8 }}>
              <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", color: "var(--muted)", fontFamily: "var(--font-display)", display: "flex", alignItems: "center", gap: 6 }}>
                <Calendar size={13} /> {usarFecha ? "Resumen del día" : "Todas las fechas"}
              </div>
              <div style={{ display: "flex", gap: 8 }}>
                <button onClick={irAHoy} style={{ fontSize: 11, color: "var(--accent)", background: "none", border: "none", fontWeight: 700, cursor: "pointer" }}>Hoy</button>
                <button onClick={() => setUsarFecha(!usarFecha)} style={{ fontSize: 11, color: "var(--muted)", background: "none", border: "none", textDecoration: "underline", cursor: "pointer" }}>
                  {usarFecha ? "Ver todas" : "Filtrar por día"}
                </button>
              </div>
            </div>
            {usarFecha && (
              <MiniCalendario fechaSeleccionada={fechaSeleccionada} onSelectFecha={setFechaSeleccionada} conteoPorDia={conteoPorDia} />
            )}
          </div>

          <div className="nvo-admin-cols" style={{ display: "flex", flex: 1, overflow: "hidden", flexDirection: "column" }}>
            <div className="nvo-admin-list-col" style={{ padding: "0 18px", overflowY: "auto", maxHeight: 280 }}>
              {lista.length === 0 && <div style={{ fontSize: 13, color: "var(--muted)", padding: "12px 0" }}>No hay registros con estos filtros.</div>}
              <div style={{ display: "flex", flexDirection: "column", gap: 6, paddingBottom: 10 }}>
                {lista.map((r) => {
                  const p = puntos.find((x) => x.id === r.puntoId);
                  const d = p ? haversine(r.lat, r.lng, p.lat, p.lng) : null;
                  const fueraDeRango = d != null && d > UMBRAL;
                  const isActive = activo?.id === r.id;
                  return (
                    <button
                      key={r.id}
                      onClick={() => { setSeleccion(r); setAmpliarFoto(false); setAmpliarMapa(false); }}
                      style={{
                        textAlign: "left",
                        display: "flex",
                        alignItems: "center",
                        gap: 10,
                        padding: "10px 12px",
                        borderRadius: 10,
                        border: isActive ? "1.5px solid var(--ink)" : "1px solid var(--line)",
                        background: isActive ? "var(--accent-soft)" : "var(--paper)",
                        cursor: "pointer",
                      }}
                    >
                      <div style={{ width: 30, height: 30, borderRadius: "50%", background: r.tipo === "entrada" ? "var(--ok)" : "var(--accent)", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                        {r.tipo === "entrada" ? <LogIn size={14} color="white" /> : <LogOut size={14} color="white" />}
                      </div>
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div style={{ fontSize: 13, fontWeight: 700, color: "var(--ink)", display: "flex", alignItems: "center", gap: 6 }}>
                          {r.mensajero}
                          <span style={{ fontSize: 10, fontWeight: 700, color: "var(--accent)", background: "var(--accent-soft)", padding: "1px 6px", borderRadius: 20 }}>
                            {p?.ciudad || mensajeros.find((m) => m.nombre === r.mensajero)?.ciudad || "—"}
                          </span>
                        </div>
                        <div style={{ fontSize: 11, color: "var(--muted)" }}>
                          {r.placa ? `${r.placa} · ` : ""}{p?.codigo} {p?.nombre} · {fmtFecha(r.timestamp)} {fmtHora(r.timestamp)}
                        </div>
                      </div>
                      {fueraDeRango && <AlertTriangle size={15} color="var(--accent)" />}
                    </button>
                  );
                })}
              </div>
            </div>

            {activo && (
              <div className="nvo-admin-detail-col" style={{ borderTop: "1px solid var(--line)", padding: 18, flex: 1, overflowY: "auto" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
                  <div>
                    <div style={{ fontFamily: "var(--font-display)", fontWeight: 800, fontSize: 16, color: "var(--ink)" }}>
                      {activo.mensajero} — {activo.tipo === "entrada" ? "Entrada" : "Salida"}
                    </div>
                    {activo.placa && (
                      <div style={{ fontSize: 12, color: "var(--accent)", fontWeight: 700, fontFamily: "monospace", marginTop: 2 }}>
                        Placa {activo.placa}
                      </div>
                    )}
                    <div style={{ fontSize: 12, color: "var(--muted)", display: "flex", alignItems: "center", gap: 5, marginTop: 2 }}>
                      <Clock size={12} /> {fmtFecha(activo.timestamp)} · {fmtHora(activo.timestamp)}
                    </div>
                    {(() => {
                      const horario = resolverHorario(activo.mensajero, activo.timestamp, mensajeros, turnos, asignaciones);
                      if (!horario) return null;
                      const diff = activo.tipo === "entrada" ? minutosDeDiferencia(activo.timestamp, horario.horaEntrada) : null;
                      return (
                        <div style={{ fontSize: 11, color: "var(--muted)", marginTop: 3 }}>
                          {horario.turnoNombre ? `Turno ${horario.turnoNombre}` : "Horario base"} ({horario.horaEntrada}–{horario.horaSalida})
                          {diff != null && (
                            <span style={{ fontWeight: 700, color: diff > TOLERANCIA_MIN ? "var(--accent)" : "var(--ok)", marginLeft: 6 }}>
                              {diff > TOLERANCIA_MIN ? `${diff} min tarde` : "A tiempo"}
                            </span>
                          )}
                        </div>
                      );
                    })()}
                  </div>
                  {distancia != null && (
                    <div style={{
                      fontSize: 11, fontWeight: 700, padding: "5px 10px", borderRadius: 20,
                      background: distancia > UMBRAL ? "#FBEAE5" : "#E5F2EC",
                      color: distancia > UMBRAL ? "var(--accent)" : "var(--ok)",
                    }}>
                      {fmtDist(distancia)} de diferencia
                    </div>
                  )}
                </div>

                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, marginBottom: 14 }}>
                  <div
                    onClick={() => setAmpliarFoto(true)}
                    style={{ cursor: "pointer", position: "relative", borderRadius: 10, overflow: "hidden", border: "1px solid var(--line)" }}
                    title="Clic para ampliar"
                  >
                    <img src={activo.foto} alt="evidencia" style={{ width: "100%", height: 180, objectFit: "cover", display: "block" }} />
                    <div style={{ position: "absolute", bottom: 6, right: 6, background: "rgba(0,0,0,0.55)", color: "white", fontSize: 10, padding: "3px 8px", borderRadius: 12, fontWeight: 600 }}>
                      Ampliar
                    </div>
                  </div>
                  <div
                    onClick={() => setAmpliarMapa(true)}
                    style={{ border: "1px solid var(--line)", borderRadius: 10, overflow: "hidden", cursor: "pointer", position: "relative" }}
                    title="Clic para ampliar"
                  >
                    <MiniMap
                      markerA={{ lat: activo.lat, lng: activo.lng }}
                      markerB={puntoActivo ? { lat: puntoActivo.lat, lng: puntoActivo.lng } : null}
                      labelA="Marcó aquí"
                      labelB={puntoActivo ? puntoActivo.codigo : "Punto"}
                    />
                    <div style={{ position: "absolute", bottom: 6, right: 6, background: "rgba(0,0,0,0.55)", color: "white", fontSize: 10, padding: "3px 8px", borderRadius: 12, fontWeight: 600 }}>
                      Ampliar
                    </div>
                  </div>
                </div>

                {ampliarFoto && (
                  <ModalAmpliar onClose={() => setAmpliarFoto(false)} titulo="Evidencia fotográfica">
                    <img src={activo.foto} alt="evidencia ampliada" style={{ maxWidth: "95vw", maxHeight: "75vh", objectFit: "contain", borderRadius: 8 }} />
                  </ModalAmpliar>
                )}
                {ampliarMapa && (
                  <ModalAmpliar onClose={() => setAmpliarMapa(false)} titulo={`Ubicación — ${activo.mensajero}`}>
                    <div style={{ width: "min(95vw, 700px)", background: "var(--paper)", borderRadius: 12, overflow: "hidden", padding: 12 }}>
                      <MiniMap
                        markerA={{ lat: activo.lat, lng: activo.lng }}
                        markerB={puntoActivo ? { lat: puntoActivo.lat, lng: puntoActivo.lng } : null}
                        labelA="Marcó aquí"
                        labelB={puntoActivo ? puntoActivo.codigo : "Punto"}
                      />
                      <div style={{ display: "flex", justifyContent: "space-between", marginTop: 10, fontSize: 12, color: "var(--ink)" }}>
                        <div><strong>Marcación:</strong> {activo.lat.toFixed(6)}, {activo.lng.toFixed(6)}</div>
                        {puntoActivo && <div><strong>Punto:</strong> {puntoActivo.lat.toFixed(6)}, {puntoActivo.lng.toFixed(6)}</div>}
                      </div>
                      {distancia != null && (
                        <div style={{ textAlign: "center", marginTop: 8, fontSize: 13, fontWeight: 700, color: distancia > UMBRAL ? "var(--accent)" : "var(--ok)" }}>
                          Distancia: {fmtDist(distancia)} {distancia > UMBRAL ? "⚠ Fuera de zona" : "✓ En zona"}
                        </div>
                      )}
                      {puntoActivo && (
                        <a
                          href={`https://www.google.com/maps/dir/${activo.lat},${activo.lng}/${puntoActivo.lat},${puntoActivo.lng}`}
                          target="_blank"
                          rel="noopener noreferrer"
                          style={{ display: "block", textAlign: "center", marginTop: 10, fontSize: 12, color: "var(--accent)", fontWeight: 700 }}
                        >
                          Ver en Google Maps ↗
                        </a>
                      )}
                    </div>
                  </ModalAmpliar>
                )}

                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, fontSize: 12 }}>
                  <div style={{ background: "var(--bg)", borderRadius: 8, padding: 10 }}>
                    <div style={{ color: "var(--muted)", fontFamily: "var(--font-display)", fontSize: 10, letterSpacing: "0.05em", textTransform: "uppercase", marginBottom: 4 }}>Ubicación marcada</div>
                    <div style={{ fontFamily: "monospace", color: "var(--ink)" }}>{activo.lat.toFixed(5)}, {activo.lng.toFixed(5)}</div>
                    <div style={{ color: "var(--muted)", marginTop: 2 }}>Precisión ±{Math.round(activo.accuracy || 0)} m</div>
                  </div>
                  <div style={{ background: "var(--bg)", borderRadius: 8, padding: 10 }}>
                    <div style={{ color: "var(--muted)", fontFamily: "var(--font-display)", fontSize: 10, letterSpacing: "0.05em", textTransform: "uppercase", marginBottom: 4 }}>Punto de referencia</div>
                    <div style={{ fontFamily: "monospace", color: "var(--ink)" }}>{puntoActivo ? `${puntoActivo.lat.toFixed(5)}, ${puntoActivo.lng.toFixed(5)}` : "—"}</div>
                    <div style={{ color: "var(--muted)", marginTop: 2 }}>{puntoActivo?.direccion}</div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </>
      )}

      {showNuevoPunto && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(14,42,82,0.5)", display: "flex", alignItems: "center", justifyContent: "center", padding: 20, zIndex: 80 }}>
          <div style={{ background: "var(--paper)", borderRadius: 14, padding: 22, width: "100%", maxWidth: 360 }}>
            <div style={{ fontFamily: "var(--font-display)", fontWeight: 800, fontSize: 16, marginBottom: 14 }}>Agregar punto fijo</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              <input placeholder="Código (ej. 130)" value={nuevoPunto.codigo} onChange={(e) => setNuevoPunto({ ...nuevoPunto, codigo: e.target.value })} style={inputStyle()} />
              <input placeholder="Nombre (ej. Cruz Verde 170)" value={nuevoPunto.nombre} onChange={(e) => setNuevoPunto({ ...nuevoPunto, nombre: e.target.value })} style={inputStyle()} />
              <select value={nuevoPunto.ciudad} onChange={(e) => setNuevoPunto({ ...nuevoPunto, ciudad: e.target.value })} style={inputStyle()}>
                {CIUDADES.map((c) => <option key={c} value={c}>{c}</option>)}
              </select>
              <input placeholder="Dirección" value={nuevoPunto.direccion} onChange={(e) => setNuevoPunto({ ...nuevoPunto, direccion: e.target.value })} style={inputStyle()} />
              <div>
                <input
                  placeholder="Pega aquí: 4.700106, -74.078328"
                  value={nuevoPunto.coordenadas}
                  onChange={(e) => setNuevoPunto({ ...nuevoPunto, coordenadas: e.target.value })}
                  style={{
                    ...inputStyle(),
                    width: "100%",
                    fontFamily: "monospace",
                    fontSize: 12.5,
                    borderColor: nuevoPunto.coordenadas
                      ? (parsearCoordenadas(nuevoPunto.coordenadas) ? "var(--ok)" : "var(--accent)")
                      : "var(--line)",
                  }}
                />
                {nuevoPunto.coordenadas && (
                  parsearCoordenadas(nuevoPunto.coordenadas) ? (
                    <div style={{ fontSize: 11, color: "var(--ok)", marginTop: 4, display: "flex", alignItems: "center", gap: 4 }}>
                      <Check size={12} /> Coordenadas válidas
                    </div>
                  ) : (
                    <div style={{ fontSize: 11, color: "var(--accent)", marginTop: 4 }}>
                      Pega el dato como lo copias de Google Maps, ej: 4.700106, -74.078328
                    </div>
                  )
                )}
              </div>
            </div>
            <div style={{ display: "flex", gap: 8, marginTop: 16 }}>
              <button onClick={() => setShowNuevoPunto(false)} style={{ flex: 1, background: "var(--bg)", border: "1px solid var(--line)", borderRadius: 8, padding: "10px", fontSize: 13, cursor: "pointer" }}>Cancelar</button>
              <button onClick={guardarPunto} style={{ flex: 1, background: "var(--ink)", color: "var(--paper)", border: "none", borderRadius: 8, padding: "10px", fontSize: 13, fontWeight: 700, cursor: "pointer" }}>Guardar</button>
            </div>
          </div>
        </div>
      )}

      {showExportar && (
        <ModalExportar
          onClose={() => setShowExportar(false)}
          onExport={(desde, hasta) => {
            exportarExcel(registros, mensajeros, puntos, turnos, asignaciones, desde, hasta);
            setShowExportar(false);
          }}
        />
      )}
    </div>
  );
}

function selStyle() {
  return { flex: 1, padding: "9px 10px", borderRadius: 8, border: "1px solid var(--line)", fontSize: 13, fontFamily: "var(--font-body)", color: "var(--ink)", background: "var(--paper)" };
}
function inputStyle() {
  return { flex: 1, padding: "10px 12px", borderRadius: 8, border: "1px solid var(--line)", fontSize: 13, fontFamily: "var(--font-body)" };
}

// ---------- App principal ----------
export default function App() {
  const [vista, setVista] = useState("selector"); // selector | mensajero | admin-login | admin
  const [mensajero, setMensajero] = useState(null);
  const [placaActual, setPlacaActual] = useState(null);
  const [origenVista, setOrigenVista] = useState("buscar-lista");
  const [ciudadDispositivo, setCiudadDispositivo] = useState(null);
  const [puntos, setPuntos] = useState(PUNTOS_DEFAULT);
  const [mensajeros, setMensajeros] = useState(MENSAJEROS_DEFAULT);
  const [turnos, setTurnos] = useState(TURNOS_DEFAULT);
  const [asignaciones, setAsignaciones] = useState([]);
  const [registros, setRegistros] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [adminPin, setAdminPin] = useState("");
  const [adminError, setAdminError] = useState("");

  useEffect(() => {
    (async () => {
      try {
        const r = await storeGet("registros", true);
        if (r?.value) setRegistros(JSON.parse(r.value));
        const p = await storeGet("puntos", true);
        if (p?.value) setPuntos(JSON.parse(p.value));
        else await storeSet("puntos", JSON.stringify(PUNTOS_DEFAULT), true);
        const mj = await storeGet("mensajeros", true);
        if (mj?.value) setMensajeros(JSON.parse(mj.value));
        else await storeSet("mensajeros", JSON.stringify(MENSAJEROS_DEFAULT), true);
        const t = await storeGet("turnos", true);
        if (t?.value) setTurnos(JSON.parse(t.value));
        else await storeSet("turnos", JSON.stringify(TURNOS_DEFAULT), true);
        const a = await storeGet("asignaciones", true);
        if (a?.value) setAsignaciones(JSON.parse(a.value));
        const cd = await storeGet("ciudad_dispositivo", false); // personal de este dispositivo
        if (cd?.value) setCiudadDispositivo(cd.value);
      } catch (e) {
        console.error(e);
      }
      setLoaded(true);
    })();
  }, []);

  const addRegistro = useCallback(async (reg) => {
    setRegistros((prev) => {
      const next = [...prev, reg];
      storeSet("registros", JSON.stringify(next), true);
      return next;
    });
  }, []);

  const addPunto = useCallback(async (punto) => {
    setPuntos((prev) => {
      const next = [...prev, punto];
      storeSet("puntos", JSON.stringify(next), true);
      return next;
    });
  }, []);

  const updateMensajero = useCallback(async (nombre, cambios) => {
    setMensajeros((prev) => {
      const next = prev.map((m) => (m.nombre === nombre ? { ...m, ...cambios } : m));
      storeSet("mensajeros", JSON.stringify(next), true);
      return next;
    });
  }, []);

  const addConductor = useCallback(async (conductor) => {
    setMensajeros((prev) => {
      const next = [...prev, conductor];
      storeSet("mensajeros", JSON.stringify(next), true);
      return next;
    });
  }, []);

  const deleteConductor = useCallback(async (nombre) => {
    setMensajeros((prev) => {
      const next = prev.filter((m) => m.nombre !== nombre);
      storeSet("mensajeros", JSON.stringify(next), true);
      return next;
    });
  }, []);

  const importarConductores = useCallback(async (lista) => {
    setMensajeros((prev) => {
      const next = [...prev, ...lista];
      storeSet("mensajeros", JSON.stringify(next), true);
      return next;
    });
  }, []);

  const addTurno = useCallback(async (turno) => {
    setTurnos((prev) => {
      const next = [...prev, turno];
      storeSet("turnos", JSON.stringify(next), true);
      return next;
    });
  }, []);

  const asignarTurno = useCallback(async ({ mensajero, fecha, turnoId }) => {
    setAsignaciones((prev) => {
      const sinDuplicado = prev.filter((a) => !(a.mensajero === mensajero && a.fecha === fecha));
      const next = [...sinDuplicado, { mensajero, fecha, turnoId }];
      storeSet("asignaciones", JSON.stringify(next), true);
      return next;
    });
  }, []);

  const quitarAsignacion = useCallback(async (mensajero, fecha) => {
    setAsignaciones((prev) => {
      const next = prev.filter((a) => !(a.mensajero === mensajero && a.fecha === fecha));
      storeSet("asignaciones", JSON.stringify(next), true);
      return next;
    });
  }, []);

  const importarMasivo = useCallback(async (filas) => {
    setAsignaciones((prev) => {
      let next = [...prev];
      filas.forEach(({ mensajero, fecha, turnoId }) => {
        next = next.filter((a) => !(a.mensajero === mensajero && a.fecha === fecha));
        next.push({ mensajero, fecha, turnoId });
      });
      storeSet("asignaciones", JSON.stringify(next), true);
      return next;
    });
  }, []);

  if (!loaded) {
    return (
      <Shell>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "center", height: "100%", color: "var(--muted)", fontSize: 13 }}>
          Cargando…
        </div>
      </Shell>
    );
  }

  return (
    <Shell wide={vista === "admin"}>
      {vista === "selector" && (
        <Bienvenida
          onBuscarLista={() => setVista("buscar-lista")}
          onAutoRegistro={() => setVista("auto-registro")}
        />
      )}
      {vista === "buscar-lista" && (
        <SelectorMensajero
          mensajeros={mensajeros}
          onSelect={(nombre) => { setMensajero(nombre); setPlacaActual(null); setOrigenVista("buscar-lista"); setVista("aceptar-terminos-a"); }}
        />
      )}
      {vista === "aceptar-terminos-a" && (
        <AceptarTerminos
          mensajero={mensajero}
          onAceptar={() => {
            const mj = mensajeros.find((m) => m.nombre === mensajero);
            const necesitaElegirCiudad = !mj?.ciudad && !ciudadDispositivo;
            setVista(necesitaElegirCiudad ? "elegir-ciudad" : "mensajero");
          }}
          onVolver={() => { setMensajero(null); setPlacaActual(null); setVista(origenVista); }}
        />
      )}
      {vista === "elegir-ciudad" && (
        <SelectorCiudadDispositivo
          ciudadesDisponibles={CIUDADES}
          onElegir={async (ciudad) => {
            setCiudadDispositivo(ciudad);
            try { await storeSet("ciudad_dispositivo", ciudad, false); } catch (e) { console.error(e); }
            setVista("mensajero");
          }}
        />
      )}
      {vista === "auto-registro" && (
        <RegistroAutonomo
          onListo={(datos) => { setMensajero(datos.nombre); setPlacaActual(datos.placa); setOrigenVista("auto-registro"); setVista("aceptar-terminos-a"); }}
        />
      )}
      {vista === "mensajero" && (
        <PanelMensajero
          mensajero={mensajero}
          placa={placaActual}
          mensajeros={mensajeros}
          puntos={puntos}
          ciudadDispositivo={ciudadDispositivo}
          registros={registros}
          onAddRegistro={addRegistro}
          onLogout={() => { setMensajero(null); setPlacaActual(null); setVista("selector"); }}
        />
      )}
      {vista === "admin-login" && (
        <div style={{ padding: 32, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", height: "100%" }}>
          <div style={{ fontFamily: "var(--font-display)", fontWeight: 800, fontSize: 18, marginBottom: 6 }}>Acceso administrador</div>
          <div style={{ fontSize: 13, color: "var(--muted)", marginBottom: 16, textAlign: "center" }}>PIN de demostración: 1234</div>
          <input
            type="password"
            value={adminPin}
            onChange={(e) => setAdminPin(e.target.value)}
            placeholder="PIN"
            style={{ ...inputStyle(), textAlign: "center", marginBottom: 10, width: 160, fontSize: 18, letterSpacing: "0.3em" }}
          />
          {adminError && <div style={{ color: "var(--accent)", fontSize: 12, marginBottom: 8 }}>{adminError}</div>}
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={() => setVista("selector")} style={{ background: "var(--bg)", border: "1px solid var(--line)", borderRadius: 8, padding: "10px 16px", fontSize: 13, cursor: "pointer" }}>Volver</button>
            <button
              onClick={() => {
                if (adminPin === "1234") { setVista("admin"); setAdminError(""); }
                else setAdminError("PIN incorrecto");
              }}
              style={{ background: "var(--ink)", color: "var(--paper)", border: "none", borderRadius: 8, padding: "10px 16px", fontSize: 13, fontWeight: 700, cursor: "pointer" }}
            >
              Entrar
            </button>
          </div>
        </div>
      )}
      {vista === "admin" && (
        <PanelAdmin
          puntos={puntos}
          registros={registros}
          mensajeros={mensajeros}
          turnos={turnos}
          asignaciones={asignaciones}
          onAddPunto={addPunto}
          onUpdateMensajero={updateMensajero}
          onAddConductor={addConductor}
          onDeleteConductor={deleteConductor}
          onImportarConductores={importarConductores}
          onAddTurno={addTurno}
          onAsignarTurno={asignarTurno}
          onQuitarAsignacion={quitarAsignacion}
          onImportarMasivo={importarMasivo}
          onBack={() => setVista("selector")}
        />
      )}
      {vista === "selector" && (
        <div style={{ textAlign: "center", paddingBottom: 24 }}>
          <button onClick={() => setVista("admin-login")} style={{ background: "none", border: "none", color: "var(--muted)", fontSize: 12, textDecoration: "underline", cursor: "pointer" }}>
            Acceso administrador
          </button>
        </div>
      )}
    </Shell>
  );
}

// ---------- Modal ampliar: foto o mapa a pantalla completa ----------
function ModalAmpliar({ children, onClose, titulo }) {
  return (
    <div
      onClick={onClose}
      style={{
        position: "fixed", inset: 0, background: "rgba(0,0,0,0.85)", zIndex: 95,
        display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
        padding: 16, cursor: "pointer",
      }}
    >
      <div style={{ color: "white", fontSize: 13, fontWeight: 700, marginBottom: 10, fontFamily: "var(--font-display)", letterSpacing: "0.05em" }}>
        {titulo || ""} <span style={{ fontWeight: 400, fontSize: 11 }}>· toca para cerrar</span>
      </div>
      <div
        onClick={(e) => e.stopPropagation()}
        style={{ maxWidth: "95vw", maxHeight: "80vh", display: "flex", alignItems: "center", justifyContent: "center", cursor: "default" }}
      >
        {children}
      </div>
      <button
        onClick={onClose}
        style={{
          marginTop: 16, background: "rgba(255,255,255,0.15)", border: "1px solid rgba(255,255,255,0.3)",
          borderRadius: 10, padding: "10px 28px", color: "white", fontSize: 14, fontWeight: 700,
          fontFamily: "var(--font-body)", cursor: "pointer",
        }}
      >
        Cerrar
      </button>
    </div>
  );
}

function Shell({ children, wide }) {
  return (
    <div
      className={wide ? "nvo-shell nvo-shell-wide" : "nvo-shell"}
      style={{
        "--bg": "#F5F6FA",
        "--paper": "#FFFFFF",
        "--ink": "#0E2A52",
        "--muted": "#6B7488",
        "--line": "#E2E5EE",
        "--accent": "#E5197E",
        "--accent-soft": "#FCE4F0",
        "--ok": "#1B8A5A",
        "--map-bg": "#EEF0F6",
        "--map-grid": "#DDE1EC",
        "--font-display": "'Archivo Black', system-ui, sans-serif",
        "--font-body": "'Inter', system-ui, sans-serif",
        background: "var(--bg)",
        minHeight: "100vh",
        maxWidth: 480,
        margin: "0 auto",
        fontFamily: "var(--font-body)",
        position: "relative",
        transition: "max-width 0.15s ease",
      }}
    >
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Archivo+Black&family=Inter:wght@400;500;600;700;800&display=swap');
        * { box-sizing: border-box; }
        input, select { outline: none; }
        input:focus, select:focus { border-color: var(--ink) !important; }
        .spin { animation: spin 1s linear infinite; }
        @keyframes spin { to { transform: rotate(360deg); } }

        /* ── MÓVIL: admin panel optimizado ── */
        @media (max-width: 899px) {
          .nvo-shell-wide { max-width: 100% !important; }
          .nvo-admin-list-col { max-height: 45vh !important; overflow-y: auto !important; }
          .nvo-admin-detail-col { max-height: none !important; padding-bottom: 24px !important; }
          .nvo-metric-grid { grid-template-columns: 1fr 1fr !important; }
        }

        /* ── PC/TABLET: el panel admin usa espacio horizontal completo ── */
        @media (min-width: 900px) {
          .nvo-shell-wide { max-width: 1200px !important; }
          .nvo-admin-cols { display: grid !important; grid-template-columns: 400px 1fr !important; gap: 0 !important; align-items: stretch; }
          .nvo-admin-cols > div { max-height: none !important; }
          .nvo-admin-list-col { border-right: 1px solid var(--line); overflow-y: auto !important; max-height: calc(100vh - 180px) !important; }
          .nvo-admin-detail-col { overflow-y: auto !important; max-height: calc(100vh - 180px) !important; border-top: none !important; }
          .nvo-metric-grid { grid-template-columns: repeat(4, 1fr) !important; }
          .nvo-calendar-row { max-width: 360px; }

          /* Filtros de Bitácora en fila en vez de apilados */
          .nvo-filtros-bitacora { display: flex; align-items: flex-start; gap: 12px; padding: 14px 18px 14px; }
          .nvo-filtros-bitacora > div { padding: 0 !important; flex: 1; }
          .nvo-filtros-bitacora > div:first-child { flex: 1.1; }

          /* Turnos: contenido no se estira a todo el ancho */
          .nvo-turnos-wrap { max-width: 520px; margin: 0 auto; }

          /* Horarios: tarjetas en grilla de 2 columnas */
          .nvo-horarios-grid { display: grid !important; grid-template-columns: 1fr 1fr !important; gap: 10px !important; align-items: start; }
          .nvo-horario-card { grid-column: span 1; }
        }

        /* ── PANTALLA GRANDE (>1200px): aún más espacio ── */
        @media (min-width: 1200px) {
          .nvo-shell-wide { max-width: 1400px !important; }
          .nvo-admin-cols { grid-template-columns: 450px 1fr !important; }
        }
      `}</style>
      {children}
    </div>
  );
}
